insert  into `e_email_templates`(`id`,`name`,`label`,`subject`,`cc_emails`,`bcc_emails`,`content`,`is_active`,`created_at`,`updated_at`) values 
(1,'contact','Liên hệ','Liên hệ mới từ website','[]','[]','<!DOCTYPE html>\r\n<html>\r\n<head>\r\n    <meta charset=\"utf-8\">\r\n    <style>\r\n        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }\r\n        .container { max-width: 600px; margin: 0 auto; padding: 20px; }\r\n        .header { background: #4e73df; color: white; padding: 20px; text-align: center; }\r\n        .content { padding: 20px; background: #f8f9fc; }\r\n        .field { margin-bottom: 15px; }\r\n        .label { font-weight: bold; color: #5a5c69; }\r\n    </style>\r\n</head>\r\n<body>\r\n    <div class=\"container\">\r\n        <div class=\"header\">\r\n            <h2>Liên hệ mới từ website</h2>\r\n        </div>\r\n        <div class=\"content\">\r\n            <div class=\"field\">\r\n                <span class=\"label\">Họ tên:</span> {{ $name }}\r\n            </div>\r\n            <div class=\"field\">\r\n                <span class=\"label\">Email:</span> {{ $email }}\r\n            </div>\r\n            <div class=\"field\">\r\n                <span class=\"label\">Số điện thoại:</span> {{ $phone }}\r\n            </div>\r\n            <div class=\"field\">\r\n                <span class=\"label\">Nội dung:</span><br>\r\n                {{ $message }}\r\n            </div>\r\n        </div>\r\n    </div>\r\n</body>\r\n</html>',1,'2025-12-26 06:26:37','2025-12-26 06:26:37'),
(2,'password_reset','Đặt lại mật khẩu','Đặt lại mật khẩu','[\"doanhelsea.hdev.one@gmail.com\"]','[\"doanhelsea.hdev.two@gmail.com\"]','<!DOCTYPE html>\r\n<html>\r\n<head>\r\n    <meta charset=\"utf-8\">\r\n    <style>\r\n        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }\r\n        .container { max-width: 600px; margin: 0 auto; padding: 20px; }\r\n        .header { background: #4e73df; color: white; padding: 20px; text-align: center; }\r\n        .content { padding: 20px; background: #f8f9fc; }\r\n        .btn { display: inline-block; padding: 12px 24px; background: #4e73df; color: white; text-decoration: none; border-radius: 4px; }\r\n    </style>\r\n</head>\r\n<body>\r\n    <div class=\"container\">\r\n        <div class=\"header\">\r\n            <h2>Đặt lại mật khẩu</h2>\r\n        </div>\r\n        <div class=\"content\">\r\n            <p>Xin chào,</p>\r\n            <p>Bạn đã yêu cầu đặt lại mật khẩu. Nhấn vào nút bên dưới để tiếp tục:</p>\r\n            <p style=\"text-align: center; margin: 30px 0;\">\r\n                <a href=\"{{ $reset_link }}\" class=\"btn\">Đặt lại mật khẩu</a>\r\n            </p>\r\n            <p>Link sẽ hết hạn sau 60 phút.</p>\r\n            <p>Nếu bạn không yêu cầu đặt lại mật khẩu, vui lòng bỏ qua email này.</p>\r\n        </div>\r\n    </div>\r\n</body>\r\n</html>',1,'2025-12-26 06:26:37','2025-12-26 06:51:42');

UNLOCK TABLES;

