/*Table structure for table `e_languages` */

DROP TABLE IF EXISTS `e_languages`;

CREATE TABLE `e_languages` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(10) COLLATE utf8_unicode_ci NOT NULL COMMENT 'Mã ngôn ngữ: vi, ja, en...',
  `name` varchar(255) COLLATE utf8_unicode_ci NOT NULL COMMENT 'Tên hiển thị: Tiếng Việt, 日本語...',
  `flag` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'Flag emoji hoặc URL ảnh',
  `flag_icon` varchar(500) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'URL to flag icon image',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '1=Ngôn ngữ mặc định',
  `is_active` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1=Hoạt động, 0=Không hoạt động',
  `position` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'Thứ tự hiển thị',
  `translations` longtext COLLATE utf8_unicode_ci COMMENT 'JSON chứa các bản dịch',
  `translations_hash` varchar(64) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'MD5 hash of translations for caching',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `e_languages_code_unique` (`code`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `e_languages` */

LOCK TABLES `e_languages` WRITE;

insert  into `e_languages`(`id`,`code`,`name`,`flag`,`flag_icon`,`is_default`,`is_active`,`position`,`translations`,`translations_hash`,`created_at`,`updated_at`) values 
(1,'vi','Tiếng Việt',NULL,'/uploads/media/2025/12/de2b21c0-a459-4318-b7d3-4830048a09db.png',0,1,1,'{\"site_name\":\"Nh\\u1eadt Vi\\u1ec7t Biotech X\\u1eed L\\u00fd N\\u01b0\\u1edbc\",\"site_description\":\"C\\u00f4ng Ty X\\u1eed L\\u00fd N\\u01b0\\u1edbc Uy T\\u00edn\",\"topbar\":{\"slogan\":\"H\\u1ec7 Th\\u1ed1ng L\\u1ecdc v\\u00e0 X\\u1eed L\\u00fd N\\u01b0\\u1edbc C\\u1ea5p, X\\u1eed L\\u00fd N\\u01b0\\u1edbc Th\\u1ea3i\"},\"header\":{\"quality_title\":\"Ch\\u1ea5t L\\u01b0\\u1ee3ng S\\u1ea3n Ph\\u1ea9m\",\"quality_desc\":\"Ti\\u00eau chu\\u1ea9n ISO 9001:2015\",\"warranty_title\":\"B\\u1ea3o H\\u00e0nh B\\u1ea3o Tr\\u00ec\",\"warranty_desc\":\"H\\u1ed7 tr\\u1ee3 24\\/7\",\"coverage_title\":\"Ph\\u1ea1m Vi Thi C\\u00f4ng\",\"coverage_desc\":\"To\\u00e0n qu\\u1ed1c\"},\"nav\":{\"home\":\"Trang Ch\\u1ee7\",\"about\":\"Gi\\u1edbi Thi\\u1ec7u\",\"services\":\"D\\u1ecbch V\\u1ee5\",\"projects\":\"D\\u1ef1 \\u00c1n\",\"news\":\"Tin T\\u1ee9c\",\"contact\":\"Li\\u00ean H\\u1ec7\",\"search_placeholder\":\"T\\u00ecm ki\\u1ebfm...\"},\"about\":{\"title\":\"Gi\\u1edbi Thi\\u1ec7u\",\"company_name\":\"C\\u00f4ng ty TNHH Gi\\u1ea3i ph\\u00e1p M\\u00f4i tr\\u01b0\\u1eddng Xanh B\\u1ec1n V\\u1eefng Nh\\u1eadt Vi\\u1ec7t\",\"description_1\":\"L\\u00e0 doanh nghi\\u1ec7p li\\u00ean doanh gi\\u1eefa Nh\\u1eadt B\\u1ea3n v\\u00e0 Vi\\u1ec7t Nam, \\u0111\\u01b0\\u1ee3c th\\u00e0nh l\\u1eadp nh\\u1eb1m k\\u1ebft h\\u1ee3p c\\u00f4ng ngh\\u1ec7 sinh h\\u1ecdc ti\\u00ean ti\\u1ebfn t\\u1eeb Nh\\u1eadt B\\u1ea3n v\\u1edbi ti\\u1ec1m n\\u0103ng ph\\u00e1t tri\\u1ec3n n\\u00f4ng nghi\\u1ec7p xanh t\\u1ea1i Vi\\u1ec7t Nam.\",\"description_2\":\"C\\u00f4ng ty l\\u00e0 th\\u00e0nh vi\\u00ean c\\u1ee7a Hi\\u1ec7p h\\u1ed9i C\\u00f4ng ngh\\u1ec7 BMW Nh\\u1eadt B\\u1ea3n \\u2013 t\\u1ed5 ch\\u1ee9c phi l\\u1ee3i nhu\\u1eadn \\u0111\\u01b0\\u1ee3c th\\u00e0nh l\\u1eadp t\\u1eeb n\\u0103m 1990, chuy\\u00ean nghi\\u00ean c\\u1ee9u, ph\\u00e1t tri\\u1ec3n v\\u00e0 ph\\u1ed5 bi\\u1ebfn c\\u00f4ng ngh\\u1ec7 BMW trong l\\u0129nh v\\u1ef1c t\\u00e1i ch\\u1ebf b\\u1ec1n v\\u1eefng, b\\u1ea3o v\\u1ec7 m\\u00f4i tr\\u01b0\\u1eddng v\\u00e0 n\\u00f4ng nghi\\u1ec7p tu\\u1ea7n ho\\u00e0n.\",\"description_3\":\"M\\u1ee5c ti\\u00eau c\\u1ee7a c\\u00f4ng ty l\\u00e0 mang c\\u00f4ng ngh\\u1ec7 BMW Nh\\u1eadt B\\u1ea3n v\\u1ec1 ph\\u1ed5 c\\u1eadp v\\u00e0 h\\u01b0\\u1edbng d\\u1eabn \\u0111\\u1ec3 ng\\u01b0\\u1eddi d\\u00e2n Vi\\u1ec7t Nam c\\u00f3 th\\u1ec3 t\\u1ef1 \\u00e1p d\\u1ee5ng, g\\u00f3p ph\\u1ea7n gi\\u1ea3i quy\\u1ebft c\\u00e1c v\\u1ea5n \\u0111\\u1ec1 v\\u1ec1 m\\u00f4i tr\\u01b0\\u1eddng n\\u00f4ng th\\u00f4n v\\u00e0 s\\u1ea3n xu\\u1ea5t n\\u00f4ng nghi\\u1ec7p t\\u1ea1i Vi\\u1ec7t Nam.\",\"feature_1\":\"Li\\u00ean Doanh Nh\\u1eadt-Vi\\u1ec7t\",\"feature_2\":\"Hi\\u1ec7p H\\u1ed9i BMW Nh\\u1eadt B\\u1ea3n\",\"feature_3\":\"C\\u00f4ng Ngh\\u1ec7 Xanh\"},\"services\":{\"title\":\"\\u1ee8ng D\\u1ee5ng C\\u00f4ng Ngh\\u1ec7 BMW\",\"subtitle\":\"N\\u01b0\\u1edbc sinh h\\u1ecdc \\u0111a n\\u0103ng BMW \\u0111\\u01b0\\u1ee3c \\u1ee9ng d\\u1ee5ng r\\u1ed9ng r\\u00e3i trong nhi\\u1ec1u l\\u0129nh v\\u1ef1c, mang l\\u1ea1i hi\\u1ec7u qu\\u1ea3 cao v\\u00e0 th\\u00e2n thi\\u1ec7n m\\u00f4i tr\\u01b0\\u1eddng\",\"detail\":\"Chi ti\\u1ebft\",\"crop_title\":\"Tr\\u1ed3ng Tr\\u1ecdt\",\"crop_desc\":\"K\\u00edch th\\u00edch n\\u1ea3y m\\u1ea7m, ra r\\u1ec5, th\\u00fac \\u0111\\u1ea9y sinh tr\\u01b0\\u1edfng, n\\u00e2ng cao n\\u0103ng su\\u1ea5t v\\u00e0 ch\\u1ea5t l\\u01b0\\u1ee3ng n\\u00f4ng s\\u1ea3n\",\"livestock_title\":\"Ch\\u0103n Nu\\u00f4i\",\"livestock_desc\":\"T\\u0103ng c\\u01b0\\u1eddng ti\\u00eau h\\u00f3a, mi\\u1ec5n d\\u1ecbch, c\\u1ea3i thi\\u1ec7n FCR, n\\u00e2ng cao ch\\u1ea5t l\\u01b0\\u1ee3ng th\\u1ecbt v\\u00e0 n\\u0103ng su\\u1ea5t s\\u1eefa\",\"aquaculture_title\":\"Th\\u1ee7y H\\u1ea3i S\\u1ea3n\",\"aquaculture_desc\":\"\\u1ed4n \\u0111\\u1ecbnh ch\\u1ea5t l\\u01b0\\u1ee3ng n\\u01b0\\u1edbc, \\u1ee9c ch\\u1ebf vi khu\\u1ea9n g\\u00e2y b\\u1ec7nh, gi\\u1ea3m chi ph\\u00ed x\\u1eed l\\u00fd m\\u00f4i tr\\u01b0\\u1eddng\",\"environment_title\":\"X\\u1eed L\\u00fd M\\u00f4i Tr\\u01b0\\u1eddng\",\"environment_desc\":\"X\\u1eed l\\u00fd b\\u1ec3 ph\\u1ed1t, \\u1ee7 ph\\u00e2n, r\\u00e1c th\\u1ea3i sinh ho\\u1ea1t, c\\u1ed1ng r\\u00e3nh v\\u00e0 ch\\u1ea5t \\u0111\\u1ec7m l\\u00f3t v\\u1eadt nu\\u00f4i\",\"lifestyle_title\":\"\\u0110\\u1eddi S\\u1ed1ng\",\"lifestyle_desc\":\"Kh\\u1eed m\\u00f9i th\\u00fa c\\u01b0ng, l\\u00e0m s\\u1ea1ch b\\u1ec3 c\\u00e1, c\\u1eafm hoa, ch\\u0103m s\\u00f3c c\\u00e2y c\\u1ea3nh, kh\\u1eed khu\\u1ea9n nh\\u00e0 b\\u1ebfp\"},\"projects\":{\"title\":\"D\\u1ef1 \\u00c1n Ti\\u00eau Bi\\u1ec3u\",\"subtitle\":\"C\\u00e1c d\\u1ef1 \\u00e1n x\\u1eed l\\u00fd n\\u01b0\\u1edbc \\u0111\\u00e3 \\u0111\\u01b0\\u1ee3c ch\\u00fang t\\u00f4i tri\\u1ec3n khai th\\u00e0nh c\\u00f4ng\",\"view_detail\":\"Xem chi ti\\u1ebft\"},\"videos\":{\"title\":\"Video - X\\u1eed L\\u00fd N\\u01b0\\u1edbc\",\"subtitle\":\"Xem c\\u00e1c video gi\\u1edbi thi\\u1ec7u s\\u1ea3n ph\\u1ea9m v\\u00e0 d\\u1ef1 \\u00e1n c\\u1ee7a ch\\u00fang t\\u00f4i\"},\"news\":{\"title\":\"Tin T\\u1ee9c & S\\u1ef1 Ki\\u1ec7n\",\"subtitle\":\"C\\u1eadp nh\\u1eadt nh\\u1eefng th\\u00f4ng tin m\\u1edbi nh\\u1ea5t v\\u1ec1 l\\u0129nh v\\u1ef1c x\\u1eed l\\u00fd n\\u01b0\\u1edbc\",\"read_more\":\"Xem th\\u00eam\",\"view_all\":\"Xem t\\u1ea5t c\\u1ea3\",\"no_news\":\"Ch\\u01b0a c\\u00f3 tin t\\u1ee9c\",\"views\":\"l\\u01b0\\u1ee3t xem\",\"video_title\":\"Video\",\"attachments\":\"T\\u1ec7p \\u0111\\u00ednh k\\u00e8m\",\"click_to_download\":\"Nh\\u1ea5n \\u0111\\u1ec3 t\\u1ea3i xu\\u1ed1ng\",\"download\":\"T\\u1ea3i xu\\u1ed1ng\",\"toc_title\":\"M\\u1ee5c l\\u1ee5c b\\u00e0i vi\\u1ebft\",\"share\":\"Chia s\\u1ebb\",\"back_to_list\":\"Quay l\\u1ea1i danh s\\u00e1ch\",\"latest_posts\":\"B\\u00e0i Vi\\u1ebft M\\u1edbi Nh\\u1ea5t\"},\"contact\":{\"title\":\"Li\\u00ean H\\u1ec7 V\\u1edbi Ch\\u00fang T\\u00f4i\",\"subtitle\":\"H\\u00e3y \\u0111\\u1ec3 