/*Table structure for table `e_media_files` */

DROP TABLE IF EXISTS `e_media_files`;

CREATE TABLE `e_media_files` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `folder_id` bigint(20) unsigned DEFAULT NULL,
  `original_name` varchar(255) COLLATE utf8_unicode_ci NOT NULL COMMENT 'Tên file gốc: image.jpg',
  `stored_name` varchar(255) COLLATE utf8_unicode_ci NOT NULL COMMENT 'Tên lưu trữ: uuid.jpg',
  `path` varchar(1000) COLLATE utf8_unicode_ci NOT NULL COMMENT 'Đường dẫn đầy đủ: /images/banner/image.jpg',
  `storage_path` varchar(1000) COLLATE utf8_unicode_ci NOT NULL COMMENT 'Đường dẫn vật lý: media/2025/12/uuid.jpg',
  `mime_type` varchar(100) COLLATE utf8_unicode_ci NOT NULL COMMENT 'image/jpeg, application/pdf',
  `file_type` enum('image','document','video','audio','other') COLLATE utf8_unicode_ci NOT NULL DEFAULT 'other',
  `file_size` bigint(20) unsigned NOT NULL COMMENT 'Kích thước (bytes)',
  `extension` varchar(20) COLLATE utf8_unicode_ci NOT NULL COMMENT 'jpg, png, pdf',
  `created_by` bigint(20) unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT 'Soft delete timestamp',
  PRIMARY KEY (`id`),
  KEY `e_media_files_created_by_foreign` (`created_by`),
  KEY `idx_folder` (`folder_id`),
  KEY `idx_file_type` (`file_type`),
  KEY `idx_path` (`path`),
  KEY `idx_deleted` (`deleted_at`),
  CONSTRAINT `e_media_files_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `e_media_files_folder_id_foreign` FOREIGN KEY (`folder_id`) REFERENCES `e_media_folders` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

