/*Table structure for table `e_media_folders` */

DROP TABLE IF EXISTS `e_media_folders`;

CREATE TABLE `e_media_folders` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) COLLATE utf8_unicode_ci NOT NULL COMMENT 'Tên thư mục',
  `parent_id` bigint(20) unsigned DEFAULT NULL,
  `path` varchar(1000) COLLATE utf8_unicode_ci NOT NULL COMMENT 'Đường dẫn đầy đủ: /images/banner',
  `created_by` bigint(20) unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT 'Soft delete timestamp',
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_path` (`path`),
  KEY `e_media_folders_created_by_foreign` (`created_by`),
  KEY `idx_parent` (`parent_id`),
  KEY `idx_path` (`path`),
  KEY `idx_deleted` (`deleted_at`),
  CONSTRAINT `e_media_folders_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `e_media_folders_parent_id_foreign` FOREIGN KEY (`parent_id`) REFERENCES `e_media_folders` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

