/*Table structure for table `e_media_logs` */

DROP TABLE IF EXISTS `e_media_logs`;

CREATE TABLE `e_media_logs` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) unsigned NOT NULL,
  `action_type` enum('upload','create_folder','rename','move','delete','restore','force_delete','empty_trash') COLLATE utf8_unicode_ci NOT NULL COMMENT 'Loại hành động',
  `target_type` enum('file','folder') COLLATE utf8_unicode_ci NOT NULL COMMENT 'Đối tượng',
  `target_path` varchar(1000) COLLATE utf8_unicode_ci NOT NULL COMMENT 'Đường dẫn mục tiêu',
  `target_name` varchar(255) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'Tên file/folder',
  `old_path` varchar(1000) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'Đường dẫn cũ (cho rename/move)',
  `details` json DEFAULT NULL COMMENT 'Thông tin bổ sung',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_action` (`action_type`),
  KEY `idx_created` (`created_at`),
  CONSTRAINT `e_media_logs_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

