/*Table structure for table `e_notifications` */

DROP TABLE IF EXISTS `e_notifications`;

CREATE TABLE `e_notifications` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) unsigned NOT NULL,
  `type` varchar(50) COLLATE utf8_unicode_ci NOT NULL,
  `action` varchar(50) COLLATE utf8_unicode_ci NOT NULL,
  `title` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `message` text COLLATE utf8_unicode_ci,
  `data` json DEFAULT NULL,
  `permission` varchar(100) COLLATE utf8_unicode_ci NOT NULL,
  `is_read` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `e_notifications_user_id_foreign` (`user_id`),
  KEY `e_notifications_permission_is_read_created_at_index` (`permission`,`is_read`,`created_at`),
  KEY `e_notifications_type_index` (`type`),
  KEY `e_notifications_permission_index` (`permission`),
  KEY `e_notifications_is_read_index` (`is_read`),
  CONSTRAINT `e_notifications_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=201 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `e_notifications` */

LOCK TABLES `e_notifications` WRITE;

