/*Table structure for table `e_post_categories` */

DROP TABLE IF EXISTS `e_post_categories`;

CREATE TABLE `e_post_categories` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `parent_id` bigint(20) unsigned DEFAULT NULL COMMENT 'ID danh mục cha',
  `created_by` bigint(20) unsigned NOT NULL,
  `position` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'Thứ tự hiển thị',
  `is_active` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Trạng thái hoạt động',
  `show_related_posts` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Hiển thị bài viết liên quan trong trang chi tiết',
  `show_in_menu` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Hiển thị trong menu website',
  `slug` varchar(255) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT 'Đường dẫn SEO',
  `names` longtext COLLATE utf8_unicode_ci COMMENT 'JSON tên theo ngôn ngữ: {"vi": "Tên VN", "en": "Name EN"}',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_created_by` (`created_by`),
  KEY `e_post_categories_parent_id_foreign` (`parent_id`),
  CONSTRAINT `e_post_categories_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `e_post_categories_parent_id_foreign` FOREIGN KEY (`parent_id`) REFERENCES `e_post_categories` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `e_post_categories` */

