/*Table structure for table `e_posts` */

DROP TABLE IF EXISTS `e_posts`;

CREATE TABLE `e_posts` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `titles` json NOT NULL COMMENT '{"vi":"...", "en":"...", "ja":"..."}',
  `slug` varchar(500) COLLATE utf8_unicode_ci DEFAULT NULL,
  `categories` json NOT NULL COMMENT 'Array of category IDs: [1, 2, 3]',
  `main_category_id` bigint(20) unsigned DEFAULT NULL,
  `author_id` bigint(20) unsigned DEFAULT NULL,
  `tags` text COLLATE utf8_unicode_ci COMMENT 'mảng JSON của thẻ bài viết',
  `album_images` text COLLATE utf8_unicode_ci COMMENT 'mảng đường dẫn ảnh',
  `attachments` text COLLATE utf8_unicode_ci COMMENT 'mảng đường dẫn tệp',
  `video_urls` text COLLATE utf8_unicode_ci COMMENT 'mảng URL video',
  `position` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'vị trí ưu tiên hiển thị',
  `view_count` int(10) unsigned NOT NULL DEFAULT '0',
  `is_featured` tinyint(1) NOT NULL DEFAULT '0' COMMENT '1=bài nổi bật, 0=bình thường',
  `show_toc` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Hiển thị table of contents',
  `main_image` varchar(255) COLLATE utf8_unicode_ci DEFAULT NULL,
  `short_descriptions` json DEFAULT NULL COMMENT 'Mô tả ngắn đa ngôn ngữ',
  `contents` json DEFAULT NULL COMMENT 'Nội dung đa ngôn ngữ',
  `seo_keywords` varchar(500) COLLATE utf8_unicode_ci DEFAULT NULL,
  `seo_title` varchar(255) COLLATE utf8_unicode_ci DEFAULT NULL,
  `seo_description` text COLLATE utf8_unicode_ci,
  `related_posts` json DEFAULT NULL COMMENT 'Array of post IDs',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1=hoạt động, 0=không hoạt động',
  `created_by` bigint(20) unsigned NOT NULL,
  `json_data` longtext COLLATE utf8_unicode_ci COMMENT 'dữ liệu bổ sung (vd lịch sử cập nhật)',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_status_featured_position` (`status`,`is_featured`,`position`),
  KEY `idx_created_by` (`created_by`),
  KEY `e_posts_main_category_id_foreign` (`main_category_id`),
  KEY `e_posts_author_id_foreign` (`author_id`),
  CONSTRAINT `e_posts_author_id_foreign` FOREIGN KEY (`author_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `e_posts_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `e_posts_main_category_id_foreign` FOREIGN KEY (`main_category_id`) REFERENCES `e_post_categories` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `e_posts` */

LOCK TABLES `e_posts` WRITE;

insert  into `e_posts`(`id`,`titles`,`slug`,`categories`,`main_category_id`,`author_id`,`tags`,`album_images`,`attachments`,`video_urls`,`position`,`view_count`,`is_featured`,`show_toc`,`main_image`,`short_descriptions`,`contents`,`seo_keywords`,`seo_title`,`seo_description`,`related_posts`,`status`,`created_by`,`json_data`,`created_at`,`updated_at`) values 
(3,'{\"en\": \"Takaichi urges business lobby to agree to above-inflation pay hikes in 2026\", \"ja\": \"１２２兆円の来年度予算案が閣議決定…過去最大の社会保障関係費・防衛費、「責任ある積極財政」路線鮮明に\", \"vi\": \"Đề xuất hoán đổi ngày làm việc để Tết Dương lịch 2026 được nghỉ 4 ngày\"}','de-xuat-hoan-doi-ngay-lam-viec-de-tet-duong-lich-2026-duoc-nghi-4-ngay','[2]',1,NULL,'[]','[\"\\/uploads\\/media\\/2025\\/12\\/420064d3-e3dc-4033-af3f-dde1f9ea0be6.png\",\"\\/uploads\\/media\\/2025\\/12\\/59e3c4c4-55c7-4c4a-9261-b7a0888489a7.png\",\"\\/uploads\\/media\\/2025\\/12\\/de2b21c0-a459-4318-b7d3-4830048a09db.png\"]','[{\"name\":\"danh_sach_duoc_lieu_huu_co_mien_bac.xlsx\",\"path\":\"\\/Doanh\\/Tin t\\u1ee9c\\/danh_sach_duoc_lieu_huu_co_mien_bac.xlsx\",\"url\":\"\\/uploads\\/media\\/2025\\/12\\/9e786af5-c056-48dc-9381-79d6e5f9f244.xlsx\"}]','[{\"type\":\"youtube\",\"url\":\"https:\\/\\/www.youtube.com\\/watch?v=GH71ao1N7vo\"}]',1,133,1,1,'/uploads/media/2025/12/a9faa39a-016d-46ff-a630-4add4afd78bc.webp','{\"en\": \"<p><span class=\\\"pull-left dateline\\\">TOKYO</span></p>\\n<div class=\\\"text-large mb-40\\\">\\n<p>Prime Minister Sanae Takaichi on Thursday urged Japanese firms to agree to pay raises above inflation in annual wage negotiations next year, as her government pursues \\\"responsible yet aggressive\\\" fiscal policies to spur growth.</p>\\n</div>\", \"ja\": \"<p>政府は２６日、一般会計総額が１２２兆３０９２億円となる２０２６年度予算案を閣議決定した。２５年度当初予算から７兆１１１４億円増え、２年連続で過去最大を更新した。税収も過去最大を見込むが、財源不足を国債発行で埋める苦しい財政運営が続いている。</p>\", \"vi\": \"<h2 class=\\\"singular-sapo\\\">(D&acirc;n tr&iacute;) - Tết Dương lịch năm 2026 rơi v&agrave;o thứ năm tuần tới, nguy&ecirc;n tắc chỉ nghỉ 1 ng&agrave;y. Bộ Nội vụ đề xuất phương &aacute;n ho&aacute;n đổi ng&agrave;y l&agrave;m việc thứ s&aacute;u liền kề để c&oacute; thể k&eacute;o d&agrave;i kỳ nghỉ 4 ng&agrave;y li&ecirc;n tiếp.</h2>\"}','{\"en\": \"<h1 class=\\\"text-xstrong mt-5 block-lg-9 block-md-10\\\">Takaichi urges business lobby to agree to above-inflation pay hikes in 2026</h1>\\n<div class=\\\"text-strong text-xsmall text-gray\\\"><time datetime=\\\"2025-12-26T06:25:00+09:00\\\">Today&nbsp;&nbsp;06:25 am JST&nbsp;&nbsp;</time><a class=\\\"text-gray\\\" href=\\\"https://japantoday.com/category/business/takaichi-urges-business-lobby-to-agree-above-inflation-pay-hikes-in-2026#comments\\\"><span class=\\\"text-primary\\\">23&nbsp;</span>Comments</a></div>\\n<div class=\\\"hr\\\">&nbsp;</div>\\n<p><span class=\\\"pull-left dateline\\\">TOKYO</span></p>\\n<div class=\\\"text-large mb-40\\\">\\n<p>Prime Minister Sanae Takaichi on Thursday urged Japanese firms to agree to pay raises above inflation in annual wage negotiations next year, as her government pursues \\\"responsible yet aggressive\\\" fiscal policies to spur growth.</p>\\n<p>\\\"I once again ask business leaders to work toward achieving base pay increases that are not eroded by rising prices,\\\" Takaichi, a fiscal dove, told a meeting organized by Japan\'s most powerful business lobby, known as Keidanren.</p>\\n<p>Takaichi, who became Japan\'s first female prime minister in October, aims to boost government revenues without raising taxes to improve consumption at a time when persistently rising prices are outpacing real-wage growth.</p>\\n<p>Yoshinobu Tsutsui, who heads Keidanren, formally the Japan Business Federation, said at the event that the lobby\'s members \\\"will work to further entrench strong momentum for wage increases.\\\"</p>\\n<p>Japan\'s annual \\\"shunto\\\" wage negotiations between management and labor unions are set to begin early next year. Many major corporations in the country close their books in March.</p>\\n</div>\", \"ja\": \"<div class=\\\"article-header\\\">\\n<h1 class=\\\"title-article c-article-title\\\">１２２兆円の来年度予算案が閣議決定&hellip;過去最大の社会保障関係費・防衛費、「責任ある積極財政」路線鮮明に</h1>\\n<div class=\\\"p-article-header-item\\\">\\n<div class=\\\"c-article-header-date\\\"><time datetime=\\\"2025-12-26T10:23\\\">2025/12/26 10:23</time>&nbsp;<time datetime=\\\"2025-12-26T10:40\\\">（2025/12/26 10:40更新）</time></div>\\n<div class=\\\"p-feature-tags\\\">&nbsp;</div>\\n<div class=\\\"p-article-action-btn-2020__article-head\\\">\\n<div class=\\\"p-article-action-btn-2020__scrap\\\"><button class=\\\"c-scrap-btn-2020 js-scrap-btn\\\" name=\\\"no_add_scrap\\\" data-article_id=\\\"\\\">保存して後で読む</button></div>\\n<ul class=\\\"p-article-action-btn-2020__share c-sns-share js-sns-share\\\">\\n<li class=\\\"sns-facebook-link\\\" data-share=\\\"facebook\\\">&nbsp;</li>\\n<li class=\\\"sns-twitter-link\\\" data-share=\\\"twitter\\\">&nbsp;</li>\\n<li class=\\\"sns-hatena-link\\\" data-share=\\\"hatena\\\">&nbsp;</li>\\n<li class=\\\"sns-share-api\\\" data-share=\\\"shareapi\\\"><a title=\\\"シェアする\\\" href=\\\"https://www.yomiuri.co.jp/economy/20251226-GYT1T00119/\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">シェア</a></li>\\n</ul>\\n</div>\\n</div>\\n</div>\\n<div class=\\\"p-main-contents \\\">\\n<div class=\\\"article-author\\\">&nbsp;</div>\\n<p class=\\\"par1\\\">　政府は２６日、一般会計総額が１２２兆３０９２億円となる２０２６年度予算案を閣議決定した。２５年度当初予算から７兆１１１４億円増え、２年連続で過去最大を更新した。税収も過去最大を見込むが、財源不足を国債発行で埋める苦しい財政運営が続いている。</p>\\n<figure id=\\\"attachment_7483289\\\" class=\\\"wp-caption none thumbnails-left\\\" aria-describedby=\\\"caption-attachment-7483289\\\">\\n<figcaption id=\\\"caption-attachment-7483289\\\" class=\\\"wp-caption-text\\\">閣議に臨む高市首相（中央）ら（２６日午前１０時、首相官邸で）＝米山要撮影</figcaption>\\n</figure>\\n<p class=\\\"par2\\\">　一般会計の総額が１２０兆円を超えるのは初めて。前年度からの増加額は２３年度（６兆７８４８億円）を上回り、過去最大となる。各省庁からの概算要求総額（１２２兆４４５４億円）を大枠で維持する予算編成で、高市内閣の「責任ある積極財政」路線が鮮明となった。</p>\\n<div id=\\\"ad_dfp_premiumrec\\\" class=\\\"p-ad-dfp-premiumrec\\\"></div>\\n<p class=\\\"par3\\\">　歳出では、社会保障関係費で過去最大の３９兆５５９億円を計上した。高額療養費制度見直しなどの制度改革で計１５００億円程度を圧縮したが、医療従事者の賃上げなどを図る診療報酬のプラス改定などに伴い７６２１億円増えた。</p>\\n<figure id=\\\"attachment_7483240\\\" class=\\\"wp-caption none thumbnails-left\\\" aria-describedby=\\\"caption-attachment-7483240\\\">\\n<figcaption id=\\\"caption-attachment-7483240\\\" class=\\\"wp-caption-text\\\">２０２６年度予算案の概要</figcaption>\\n</figure>\\n<p class=\\\"par4\\\">　米軍再編関係費などを含む防衛費も３３４９億円増の９兆３５３億円で過去最大を更新した。政府は防衛力整備計画で２３年度から５年間の防衛費の総額を約４３兆円とする方針を示しており、４年目となる２６年度は対象経費として８兆８０９３億円を計上した。</p>\\n<p class=\\\"par5\\\">　地方自治体の財源となる地方交付税交付金等は２０兆８７７８億円を計上した。自動車の購入時に課税する「環境性能割」の廃止などに伴い、地方税収の減少分を交付金で手当てする。</p>\\n<p class=\\\"par6\\\">　高校授業料無償化の拡充や小学校の給食無償化などでは、国の負担分として約３７００億円を積み増した。</p>\\n<p class=\\\"par7\\\">　国の借金の償還や利払いに充てる国債費は前年度比３兆５７９億円増の３１兆２７５８億円で、初めて３０兆円を超えた。債券市場の動きを受けて想定金利を２５年度の年２・０％から年３・０％に引き上げたため、利払い費が２・５兆円増えて１３兆円に膨らむ。</p>\\n<p class=\\\"par8\\\">　歳入は、税収が７年連続の過去最高となる８３兆７３５０億円と見積もった。物価高や好調な企業業績を背景に、所得税、法人税、消費税の基幹３税でいずれも大幅増を見込む。</p>\\n<figure id=\\\"attachment_7483238\\\" class=\\\"wp-caption none thumbnails-left\\\" aria-describedby=\\\"caption-attachment-7483238\\\">\\n<figcaption id=\\\"caption-attachment-7483238\\\" class=\\\"wp-caption-text\\\">税収と新規国債発行額</figcaption>\\n</figure>\\n<p class=\\\"par9\\\">　新規国債発行額は２９兆５８４０億円で、前年度から９３６９億円増えた。内訳は公共事業費などの財源となる建設国債が６兆７１６０億円、赤字国債が２２兆８６８０億円。歳入に占める新規国債発行の割合を示す公債依存度は２４・２％だった。２７年ぶりに３０％を下回った２５年度（２４・９％）をさらに下回った。</p>\\n<p class=\\\"par10\\\">　政府は２６年１月に召集される通常国会に予算案を提出し、３月末までの成立を目指す。</p>\\n</div>\", \"vi\": \"<h1 class=\\\"title-page detail\\\">Đề xuất ho&aacute;n đổi ng&agrave;y l&agrave;m việc để Tết Dương lịch 2026 được nghỉ 4 ng&agrave;y</h1>\\n<div class=\\\"author-wrap\\\">&nbsp;</div>\\n<h2 class=\\\"singular-sapo\\\">(D&acirc;n tr&iacute;) - Tết Dương lịch năm 2026 rơi v&agrave;o thứ năm tuần tới, nguy&ecirc;n tắc chỉ nghỉ 1 ng&agrave;y. Bộ Nội vụ đề xuất phương &aacute;n ho&aacute;n đổi ng&agrave;y l&agrave;m việc thứ s&aacute;u liền kề để c&oacute; thể k&eacute;o d&agrave;i kỳ nghỉ 4 ng&agrave;y li&ecirc;n tiếp.</h2>\\n<div class=\\\"singular-content\\\">\\n<p>Bộ Nội vụ vừa c&oacute; đề xuất mới về phương &aacute;n nghỉ&nbsp;<a contenteditable=\\\"false\\\" href=\\\"https://dantri.com.vn/noi-vu/chi-tiet-lich-nghi-tet-duong-lich-nam-2026-20251130205641394.htm\\\">Tết Dương lịch</a>&nbsp;năm 2026. Phương &aacute;n n&ecirc;u ra đang được lấy &yacute; kiến c&aacute;c bộ, ng&agrave;nh.</p>\\n<p>Theo đ&oacute;, cơ quan n&agrave;y đề xuất nghỉ ng&agrave;y 1/1/2026 dương lịch theo quy định; ho&aacute;n đổi từ ng&agrave;y l&agrave;m việc thứ s&aacute;u (ng&agrave;y 2/1/2026) sang ng&agrave;y nghỉ hằng tuần thứ bảy (ng&agrave;y 10/1/2026).</p>\\n<figure class=\\\"image align-center\\\"><img class=\\\"entered loaded\\\" title=\\\"Đề xuất ho&aacute;n đổi ng&agrave;y l&agrave;m việc để Tết Dương lịch 2026 được nghỉ 4 ng&agrave;y - 1\\\" src=\\\"https://cdnphoto.dantri.com.vn/1xQtQMKeykCNtrSC4OqBJfAH3ms=/thumb_w/1020/2025/12/24/de-xuat-hoan-doi-ngay-lam-viec-de-tet-duong-lich-2026-duoc-nghi-4-ngay-1766548928836.jpg\\\" srcset=\\\"https://cdnphoto.dantri.com.vn/1xQtQMKeykCNtrSC4OqBJfAH3ms=/thumb_w/1020/2025/12/24/de-xuat-hoan-doi-ngay-lam-viec-de-tet-duong-lich-2026-duoc-nghi-4-ngay-1766548928836.jpg 1x, https://cdnphoto.dantri.com.vn/nLoUhSDhgVNUAD_4jZNzPPmP9zs=/thumb_w/1360/2025/12/24/de-xuat-hoan-doi-ngay-lam-viec-de-tet-duong-lich-2026-duoc-nghi-4-ngay-1766548928836.jpg 2x\\\" alt=\\\"Đề xuất ho&aacute;n đổi ng&agrave;y l&agrave;m việc để Tết Dương lịch 2026 được nghỉ 4 ng&agrave;y - 1\\\" data-width=\\\"1360\\\" data-height=\\\"1173\\\" data-original=\\\"https://cdnphoto.dantri.com.vn/xql-7_hyNcxL7Ai5UyZAENLoKpc=/2025/12/24/de-xuat-hoan-doi-ngay-lam-viec-de-tet-duong-lich-2026-duoc-nghi-4-ngay-1766548928836.jpg\\\" data-photo-id=\\\"3815893\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-image\\\" data-content-piece=\\\"article-content-image_3815893\\\" data-content-target=\\\"/noi-vu/de-xuat-hoan-doi-ngay-lam-viec-de-tet-duong-lich-2026-duoc-nghi-4-ngay-20251224100833048.htm\\\" data-src=\\\"https://cdnphoto.dantri.com.vn/1xQtQMKeykCNtrSC4OqBJfAH3ms=/thumb_w/1020/2025/12/24/de-xuat-hoan-doi-ngay-lam-viec-de-tet-duong-lich-2026-duoc-nghi-4-ngay-1766548928836.jpg\\\" data-srcset=\\\"https://cdnphoto.dantri.com.vn/1xQtQMKeykCNtrSC4OqBJfAH3ms=/thumb_w/1020/2025/12/24/de-xuat-hoan-doi-ngay-lam-viec-de-tet-duong-lich-2026-duoc-nghi-4-ngay-1766548928836.jpg 1x, https://cdnphoto.dantri.com.vn/nLoUhSDhgVNUAD_4jZNzPPmP9zs=/thumb_w/1360/2025/12/24/de-xuat-hoan-doi-ngay-lam-viec-de-tet-duong-lich-2026-duoc-nghi-4-ngay-1766548928836.jpg 2x\\\" data-ll-status=\\\"loaded\\\">\\n<figcaption>\\n<p>Tết Dương lịch năm 2026 rơi v&agrave;o thứ năm, ng&agrave;y 1/1/2026 (Ảnh minh họa).</p>\\n</figcaption>\\n</figure>\\n<p>Nếu đề xuất n&agrave;y được th&ocirc;ng qua, dịp tết Dương lịch năm 2026, c&ocirc;ng chức, vi&ecirc;n chức được nghỉ 4 ng&agrave;y li&ecirc;n tục từ thứ năm ng&agrave;y 1/1/2026 dương lịch đến hết chủ nhật ng&agrave;y 4/1/2026 dương lịch. Trong đ&oacute;, c&oacute; 2 ng&agrave;y nghỉ li&ecirc;n tiếp do ho&aacute;n đổi với ng&agrave;y l&agrave;m việc v&agrave; 2 ng&agrave;y nghỉ hằng tuần.</p>\\n<p>Bộ Nội vụ cho biết đề xuất n&agrave;y cũng khuyến kh&iacute;ch người sử dụng lao động &aacute;p dụng thời gian nghỉ tết Dương lịch năm 2026 cho người lao động như quy định đối với c&ocirc;ng chức, vi&ecirc;n chức nhưng đảm bảo thực hiện đầy đủ c&aacute;c chế độ cho người lao động theo quy định của ph&aacute;p luật; khuyến kh&iacute;ch những thỏa thuận c&oacute; lợi hơn cho người lao động.</p>\\n<p>Trước đ&oacute;, theo th&ocirc;ng b&aacute;o của Bộ Nội vụ về c&aacute;c dịp nghỉ lễ, Tết năm 2026,&nbsp;kỳ nghỉ Tết Nguy&ecirc;n đ&aacute;n, c&aacute;n bộ, c&ocirc;ng chức, vi&ecirc;n chức v&agrave; người lao động của c&aacute;c cơ quan h&agrave;nh ch&iacute;nh, sự nghiệp, tổ chức ch&iacute;nh trị, tổ chức ch&iacute;nh trị - x&atilde; hội được nghỉ 5 ng&agrave;y theo quy định, gồm 1 ng&agrave;y trước Tết v&agrave; 4 ng&agrave;y sau Tết.</p>\\n<aside data-module=\\\"related-article-in-content\\\" data-id=\\\"20251130205641394\\\" data-index=\\\"0\\\">\\n<article class=\\\"dt-float-right dt-ml-5 dt-mb-5 dt-p-5 dt-bg-[#F3F6F6] dt-border-y-2 dt-border-y-[#FF8F2C] dt-flex dt-flex-col dt-gap-3 dt-relative dt-z-[1]\\\" data-track-content=\\\"true\\\" data-content-name=\\\"article-related-box\\\" data-content-piece=\\\"article-related-box-position_01\\\" data-content-target=\\\"/noi-vu/chi-tiet-lich-nghi-tet-duong-lich-nam-2026-20251130205641394.htm\\\">\\n<div class=\\\"dt-flex dt-gap-[5px] dt-items-center dt-font-inter dt-text-common-sub dt-font-semibold dt-text-xs dt-leading-5\\\">TIN LI&Ecirc;N QUAN</div>\\n<h3 class=\\\"!dt-font-inter !dt-font-semibold !dt-text-base !dt-leading-22px xl:!dt-text-lg xl:!dt-leading-26px\\\"><a class=\\\"!dt-text-black hover:!dt-text-black\\\" title=\\\"Chi tiết lịch nghỉ Tết Dương lịch năm 2026\\\" href=\\\"https://dantri.com.vn/noi-vu/chi-tiet-lich-nghi-tet-duong-lich-nam-2026-20251130205641394.htm\\\">Chi tiết lịch nghỉ Tết Dương lịch năm 2026</a></h3>\\n</article>\\n</aside>\\n<p>Như vậy, kỳ nghỉ Tết ch&iacute;nh thức bắt đầu từ thứ hai ng&agrave;y 16/2/2026 (tức ng&agrave;y 29 th&aacute;ng Chạp năm Ất Tỵ) đến hết thứ s&aacute;u, ng&agrave;y 20/2/2026 (tức ng&agrave;y m&ugrave;ng 4 th&aacute;ng Gi&ecirc;ng năm B&iacute;nh Ngọ).</p>\\n<p>C&ugrave;ng với 5 ng&agrave;y nghỉ Tết, c&aacute;n bộ, c&ocirc;ng chức được nghỉ nối tiếp 4 ng&agrave;y nghỉ hằng tuần. Khối cơ quan khu vực c&ocirc;ng c&oacute; kỳ nghỉ tới 9 ng&agrave;y li&ecirc;n tiếp.</p>\\n<p>Đối với người lao động, người sử dụng lao động khu vực ngo&agrave;i c&ocirc;ng lập, đơn vị quyết định lựa chọn phương &aacute;n nghỉ Tết Nguy&ecirc;n đ&aacute;n như sau: Lựa chọn nghỉ 1 ng&agrave;y cuối năm Ất Tỵ v&agrave; 4 ng&agrave;y đầu năm B&iacute;nh Ngọ hoặc 2 ng&agrave;y cuối năm Ất Tỵ v&agrave; 3 ng&agrave;y đầu năm B&iacute;nh Ngọ hoặc 3 ng&agrave;y cuối năm Ất Tỵ v&agrave; 2 ng&agrave;y đầu năm B&iacute;nh Ngọ.</p>\\n<p>Với dịp lễ Quốc kh&aacute;nh, c&ocirc;ng chức, vi&ecirc;n chức được nghỉ 2 ng&agrave;y theo quy định, gồm ng&agrave;y 2/9/2026 v&agrave; 1 ng&agrave;y liền kề trước l&agrave; ng&agrave;y 1/9/2026. Cả nước cũng thực hiện ho&aacute;n đổi từ ng&agrave;y l&agrave;m việc thứ hai, ng&agrave;y 31/8/2026, sang ng&agrave;y nghỉ hằng tuần thứ bảy, ng&agrave;y 22/8/2026 (nghỉ thứ hai, ng&agrave;y 31/8/2026, v&agrave; l&agrave;m b&ugrave; v&agrave;o thứ bảy, ng&agrave;y 22/8/2026).</p>\\n<p>Như vậy, c&ugrave;ng với ng&agrave;y nghỉ hằng tuần v&agrave; nghỉ lễ, c&aacute;n bộ, c&ocirc;ng chức được nghỉ 5 ng&agrave;y li&ecirc;n tiếp dịp n&agrave;y.</p>\\n<p>Với người lao động khu vực doanh nghiệp, dịp lễ Quốc kh&aacute;nh sẽ được nghỉ thứ tư ng&agrave;y 2/9/2026 v&agrave; lựa chọn nghỉ 1 trong 2 ng&agrave;y: thứ ba, ng&agrave;y 1/9/2026, hoặc thứ năm, ng&agrave;y 3/9/2026.</p>\\n<p>Ngo&agrave;i 3 dịp nghỉ lễ tr&ecirc;n, c&aacute;n bộ, c&ocirc;ng chức c&ograve;n được nghỉ ng&agrave;y Giỗ Tổ H&ugrave;ng Vương (10/3 &acirc;m lịch), ng&agrave;y 30/4 (Chiến thắng), ng&agrave;y 1/5 (Quốc tế lao động).</p>\\n</div>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2025-12-26 03:42:51','2026-01-06 14:37:29'),
(4,'{\"en\": \"Tiếng anh\", \"ja\": \"Tiếng nhật\", \"vi\": \"Nga tiết lộ tình hình ở Venezuela sau chiến dịch tấn công của Mỹ\"}','nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my','[1]',1,NULL,'[]','[\"\\/uploads\\/media\\/2025\\/12\\/de2b21c0-a459-4318-b7d3-4830048a09db.png\",\"\\/uploads\\/media\\/2025\\/12\\/59e3c4c4-55c7-4c4a-9261-b7a0888489a7.png\"]','[]','[]',2,279,1,1,'/uploads/media/2025/12/420064d3-e3dc-4033-af3f-dde1f9ea0be6.png','{\"en\": \"<h2 class=\\\"singular-sapo\\\">(D&acirc;n tr&iacute;) - Đại sứ Nga cho biết t&igrave;nh h&igrave;nh ở Venezuela hiện vẫn nằm dưới sự kiểm so&aacute;t của ch&iacute;nh quyền sau cuộc kh&ocirc;ng k&iacute;ch của Mỹ.</h2>\", \"ja\": \"<h2 class=\\\"singular-sapo\\\">(D&acirc;n tr&iacute;) - Đại sứ Nga cho biết t&igrave;nh h&igrave;nh ở Venezuela hiện vẫn nằm dưới sự kiểm so&aacute;t của ch&iacute;nh quyền sau cuộc kh&ocirc;ng k&iacute;ch của Mỹ.</h2>\", \"vi\": \"<h2 class=\\\"singular-sapo\\\">(D&acirc;n tr&iacute;) - Đại sứ Nga cho biết t&igrave;nh h&igrave;nh ở Venezuela hiện vẫn nằm dưới sự kiểm so&aacute;t của ch&iacute;nh quyền sau cuộc kh&ocirc;ng k&iacute;ch của Mỹ.</h2>\"}','{\"en\": \"<h1 class=\\\"title-page detail\\\">Tiếng Anh</h1>\\n<h1 class=\\\"title-page detail\\\">Nga tiết lộ t&igrave;nh h&igrave;nh ở Venezuela sau chiến dịch tấn c&ocirc;ng của Mỹ</h1>\\n<div class=\\\"author-wrap\\\">&nbsp;</div>\\n<div data-module=\\\"article-audio-new\\\" data-article-id=\\\"20260104180808480\\\" data-vast-url=\\\"https://pubads.g.doubleclick.net/gampad/ads?iu=/21899300285/dtadnetwork/audio&amp;description_url=https%3A%2F%2Fdantri.com.vn%2Fthe-gioi%2Fnga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm&amp;tfcd=0&amp;npa=0&amp;ad_type=audio&amp;sz=1x1&amp;gdfp_req=1&amp;output=vast&amp;unviewed_position_start=1&amp;env=vp&amp;impl=s&amp;wta=1&amp;plcmt=2&amp;correlator=\\\">\\n<div id=\\\"article-audio\\\">\\n<div>\\n<div class=\\\"j82SeqF_gxPVzIvNth9w\\\">\\n<div class=\\\"ySrzD84SzXaFjeHOPSdl\\\">\\n<div class=\\\"odifykg1Hpy_xVPsO7bL\\\">\\n<div class=\\\"hPoPnm_sPRyVcwvbMcGw\\\">&nbsp;</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n<h2 class=\\\"singular-sapo\\\">(D&acirc;n tr&iacute;) - Đại sứ Nga cho biết t&igrave;nh h&igrave;nh ở Venezuela hiện vẫn nằm dưới sự kiểm so&aacute;t của ch&iacute;nh quyền sau cuộc kh&ocirc;ng k&iacute;ch của Mỹ.</h2>\\n<div class=\\\"singular-content\\\">\\n<figure class=\\\"image align-center\\\"><img class=\\\"entered loaded\\\" title=\\\"Nga tiết lộ t&igrave;nh h&igrave;nh ở Venezuela sau chiến dịch tấn c&ocirc;ng của Mỹ - 1\\\" src=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg\\\" srcset=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg 1x, https://cdnphoto.dantri.com.vn/nxqStk-M8qAStdJHh3h9ttEc880=/thumb_w/1360/2026/01/03/xe-bus-1767453244829.jpg 2x\\\" alt=\\\"Nga tiết lộ t&igrave;nh h&igrave;nh ở Venezuela sau chiến dịch tấn c&ocirc;ng của Mỹ - 1\\\" data-width=\\\"700\\\" data-height=\\\"467\\\" data-original=\\\"https://cdnphoto.dantri.com.vn/WDJ0h_XUblJHeVUgB0mMduHZh24=/2026/01/03/xe-bus-1767453244829.jpg\\\" data-photo-id=\\\"3831271\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-image\\\" data-content-piece=\\\"article-content-image_3831271\\\" data-content-target=\\\"/the-gioi/nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm\\\" data-src=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg\\\" data-srcset=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg 1x, https://cdnphoto.dantri.com.vn/nxqStk-M8qAStdJHh3h9ttEc880=/thumb_w/1360/2026/01/03/xe-bus-1767453244829.jpg 2x\\\" data-ll-status=\\\"loaded\\\">\\n<figcaption>\\n<p>C&aacute;c phương tiện bị ph&aacute; hủy tại căn cứ kh&ocirc;ng qu&acirc;n La Carlota ở Caracas, Venezuela ng&agrave;y 3/1 (Ảnh: Reuters).</p>\\n</figcaption>\\n</figure>\\n<p>Đại sứ Nga tại Venezuela Sergey Melik-Bagdasarov n&oacute;i với h&atilde;ng th&ocirc;ng tấn TASS rằng, t&igrave;nh h&igrave;nh tại thủ đ&ocirc; Caracas của Venezuela hiện y&ecirc;n tĩnh v&agrave; vẫn nằm dưới sự kiểm so&aacute;t của ch&iacute;nh quyền sau cuộc kh&ocirc;ng k&iacute;ch của Mỹ.</p>\\n<p>\\\"T&igrave;nh h&igrave;nh ở Caracas hiện y&ecirc;n tĩnh v&agrave; ho&agrave;n to&agrave;n được ch&iacute;nh quyền kiểm so&aacute;t. Tuy nhi&ecirc;n, rất &iacute;t người ra đường, điều n&agrave;y thường &iacute;t xảy ra v&agrave;o ng&agrave;y cuối tuần&rdquo;, &ocirc;ng Melik-Bagdasarov cho biết h&ocirc;m 4/1.</p>\\n<p>&ldquo;R&otilde; r&agrave;ng, điều n&agrave;y kh&ocirc;ng chỉ được l&yacute; giải bởi t&acirc;m l&yacute; b&agrave;ng ho&agrave;ng sau vụ tấn c&ocirc;ng đ&ecirc;m qua, khiến người d&acirc;n vẫn c&ograve;n chịu ảnh hưởng, m&agrave; c&ograve;n bởi sự quan t&acirc;m của họ đến những&nbsp;<a href=\\\"https://dantri.com.vn/\\\" data-auto-link-id=\\\"5fd3362e5333a60018f3a1de\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-autolink\\\" data-content-piece=\\\"article-content-autolink_5fd3362e5333a60018f3a1de\\\" data-content-target=\\\"/the-gioi/nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm\\\">tin tức</a>&nbsp;đ&aacute;ng b&aacute;o động\\\", &ocirc;ng n&oacute;i, đồng thời cho biết Đại sứ qu&aacute;n Nga v&agrave; c&aacute;c ph&aacute;i đo&agrave;n ngoại giao kh&aacute;c của Nga tại Venezuela kh&ocirc;ng bị thiệt hại trong vụ tấn c&ocirc;ng của Mỹ.</p>\\n<p>Theo nh&agrave; ngoại giao Nga, kh&ocirc;ng c&oacute; c&ocirc;ng d&acirc;n Nga thiệt mạng hoặc bị thương trong cuộc kh&ocirc;ng k&iacute;ch của Mỹ v&agrave;o Venezuela v&agrave; Nga &ldquo;tiếp tục theo d&otilde;i t&igrave;nh h&igrave;nh&rdquo;.</p>\\n<p>\\\"Đại sứ qu&aacute;n đang l&agrave;m việc suốt ng&agrave;y đ&ecirc;m v&agrave; duy tr&igrave; li&ecirc;n lạc với Moscow, ch&iacute;nh phủ v&agrave; c&aacute;c cơ quan thực thi ph&aacute;p luật cũng đang phối hợp hoạt động. C&aacute;c biện ph&aacute;p an ninh đ&atilde; được tăng cường&rdquo;, Đại sứ Melik-Bagdasarov n&oacute;i th&ecirc;m.</p>\\n<p>Theo nh&agrave; ngoại giao Nga, Đại sứ qu&aacute;n Nga đ&atilde; nhận được nhiều cuộc gọi từ c&ocirc;ng d&acirc;n Nga đang sinh sống tại Venezuela v&agrave; từ người th&acirc;n của họ.</p>\\n<p>\\\"Ch&uacute;ng t&ocirc;i k&ecirc;u gọi người d&acirc;n kh&ocirc;ng n&ecirc;n hoảng loạn, tr&aacute;nh đến những nơi đ&ocirc;ng người, cũng như tr&aacute;nh ở gần c&aacute;c cơ sở qu&acirc;n sự, cơ sở năng lượng v&agrave; cơ sở truyền th&ocirc;ng, những nơi c&oacute; thể trở th&agrave;nh mục ti&ecirc;u trong trường hợp xảy ra c&aacute;c cuộc tấn c&ocirc;ng tiếp theo. Cuộc tấn c&ocirc;ng đ&ecirc;m qua đ&atilde; chứng minh rằng Mỹ biết ch&iacute;nh x&aacute;c vị tr&iacute; cần tấn c&ocirc;ng v&agrave; muốn ngăn chặn thương vong nặng nề cho d&acirc;n thường&rdquo;, Đại sứ Nga n&ecirc;u r&otilde;.</p>\\n<p>Ng&agrave;y 3/1, Ngoại trưởng Venezuela Yvan Gil Pinto x&aacute;c nhận Mỹ đ&atilde; tấn c&ocirc;ng c&aacute;c cơ sở d&acirc;n sự v&agrave;&nbsp;<a href=\\\"https://dantri.com.vn/the-gioi/quan-su.htm\\\" data-auto-link-id=\\\"6137992efb044100119a147e\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-autolink\\\" data-content-piece=\\\"article-content-autolink_6137992efb044100119a147e\\\" data-content-target=\\\"/the-gioi/nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm\\\">qu&acirc;n sự</a>&nbsp;ở Caracas. &Ocirc;ng l&ecirc;n &aacute;n cuộc kh&ocirc;ng k&iacute;ch của Washington l&agrave; h&agrave;nh động g&acirc;y hấn qu&acirc;n sự.</p>\\n<p>T&igrave;nh trạng khẩn cấp đ&atilde; được ban bố ở Venezuela. Tổng thống Mỹ Donald Trump đ&atilde; x&aacute;c nhận vụ tấn c&ocirc;ng v&agrave;o Venezuela. Theo nh&agrave; l&atilde;nh đạo Mỹ, Tổng thống Venezuela Nicolas Maduro v&agrave; vợ đ&atilde; bị bắt giữ v&agrave; đưa ra khỏi đất nước.</p>\\n<aside data-module=\\\"related-article-in-content\\\" data-id=\\\"20260104163820305\\\" data-index=\\\"0\\\">\\n<article class=\\\"dt-float-right dt-ml-5 dt-mb-5 dt-p-5 dt-bg-[#F3F6F6] dt-border-y-2 dt-border-y-[#FF8F2C] dt-flex dt-flex-col dt-gap-3 dt-relative dt-z-[1]\\\" data-track-content=\\\"true\\\" data-content-name=\\\"article-related-box\\\" data-content-piece=\\\"article-related-box-position_01\\\" data-content-target=\\\"/the-gioi/tong-thong-trump-lam-ro-tuyen-bo-dieu-hanh-venezuela-sau-cuoc-khong-kich-20260104163820305.htm\\\">\\n<div class=\\\"dt-flex dt-gap-[5px] dt-items-center dt-font-inter dt-text-common-sub dt-font-semibold dt-text-xs dt-leading-5\\\">TIN LI&Ecirc;N QUAN</div>\\n<h3 class=\\\"!dt-font-inter !dt-font-semibold !dt-text-base !dt-leading-22px xl:!dt-text-lg xl:!dt-leading-26px\\\"><a class=\\\"!dt-text-black hover:!dt-text-black\\\" title=\\\"Tổng thống Trump l&agrave;m r&otilde; tuy&ecirc;n bố &ldquo;điều h&agrave;nh Venezuela&rdquo; sau cuộc kh&ocirc;ng k&iacute;ch\\\" href=\\\"https://dantri.com.vn/the-gioi/tong-thong-trump-lam-ro-tuyen-bo-dieu-hanh-venezuela-sau-cuoc-khong-kich-20260104163820305.htm\\\">Tổng thống Trump l&agrave;m r&otilde; tuy&ecirc;n bố &ldquo;điều h&agrave;nh Venezuela&rdquo; sau cuộc kh&ocirc;ng k&iacute;ch</a></h3>\\n</article>\\n</aside>\\n<p>Bộ Ngoại giao Nga b&agrave;y tỏ quan ngại s&acirc;u sắc về h&agrave;nh động qu&acirc;n sự của Mỹ đối với Venezuela v&agrave; l&ecirc;n &aacute;n mạnh mẽ cuộc tấn c&ocirc;ng n&agrave;y. Trong t&igrave;nh h&igrave;nh n&agrave;y, Nga cho rằng điều cần thiết tr&ecirc;n hết l&agrave; ngăn chặn sự leo thang hơn nữa v&agrave; tập trung v&agrave;o việc t&igrave;m kiếm giải ph&aacute;p th&ocirc;ng qua đối thoại. Bộ Ngoại giao Nga y&ecirc;u cầu Mỹ ngay lập tức trả tự do cho Tổng thống Maduro v&agrave; vợ &ocirc;ng.</p>\\n<p>Bộ Ngoại giao Nga đ&atilde; l&ecirc;n &aacute;n h&agrave;nh động bắt giữ của Mỹ, đồng thời nhấn mạnh bất cứ l&yacute; do n&agrave;o biện minh cho những h&agrave;nh động đ&oacute; l&agrave; &ldquo;kh&ocirc;ng thể chấp nhận được&rdquo;. Theo Bộ Ngoại giao Nga, \\\"việc t&ocirc;n trọng chủ quyền l&agrave; một nguy&ecirc;n tắc then chốt của luật ph&aacute;p quốc tế\\\".</p>\\n<p>V&agrave;o tối 3/1, T&ograve;a &aacute;n Tối cao Venezuela đ&atilde; chỉ định Ph&oacute; Tổng thống Rodriguez trở th&agrave;nh l&atilde;nh đạo l&acirc;m thời của Venezuela.</p>\\n<p>T&ograve;a &aacute;n tối cao Venezuela đ&atilde; ph&aacute;n quyết rằng b&agrave; Rodriguez sẽ &ldquo;đảm nhiệm v&agrave; thực hiện, với tư c&aacute;ch l&agrave; người tạm quyền, tất cả nhiệm vụ v&agrave; quyền hạn vốn c&oacute; của Tổng thống&hellip; để đảm bảo t&iacute;nh li&ecirc;n tục của ch&iacute;nh quyền v&agrave; quốc ph&ograve;ng to&agrave;n diện của quốc gia&rdquo;.</p>\\n<p><strong>Kế hoạch của Mỹ sau chiến dịch kh&ocirc;ng k&iacute;ch</strong></p>\\n<p>Trong cuộc họp b&aacute;o sau chiến dịch kh&ocirc;ng k&iacute;ch Venezuela, Tổng thống Mỹ Donald Trump đ&atilde; n&ecirc;u một số kịch bản mới đối với quốc gia Nam Mỹ.</p>\\n<aside data-module=\\\"related-article-in-content\\\" data-id=\\\"20260104172818185\\\" data-index=\\\"1\\\">\\n<article class=\\\"dt-float-right dt-ml-5 dt-mb-5 dt-p-5 dt-bg-[#F3F6F6] dt-border-y-2 dt-border-y-[#FF8F2C] dt-flex dt-flex-col dt-gap-3 dt-relative dt-z-[1]\\\" data-track-content=\\\"true\\\" data-content-name=\\\"article-related-box\\\" data-content-piece=\\\"article-related-box-position_11\\\" data-content-target=\\\"/the-gioi/ty-phu-musk-mien-phi-internet-starlink-tai-venezuela-den-dau-thang-2-20260104172818185.htm\\\">\\n<div class=\\\"dt-flex dt-gap-[5px] dt-items-center dt-font-inter dt-text-common-sub dt-font-semibold dt-text-xs dt-leading-5\\\">TIN LI&Ecirc;N QUAN</div>\\n<a class=\\\"dt-w-full dt-cursor-pointer\\\" title=\\\"Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2\\\" href=\\\"https://dantri.com.vn/the-gioi/ty-phu-musk-mien-phi-internet-starlink-tai-venezuela-den-dau-thang-2-20260104172818185.htm\\\"><img class=\\\"dt-w-full dt-aspect-3/2\\\" src=\\\"https://cdnphoto.dantri.com.vn/hxUumo7USM5CU4FOqhflVLMW0HY=/thumb_w/768/2026/01/04/elonmusk-cropped-1767522375092.jpg\\\" alt=\\\"Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2\\\"></a>\\n<h3 class=\\\"!dt-font-inter !dt-font-semibold !dt-text-base !dt-leading-22px xl:!dt-text-lg xl:!dt-leading-26px\\\"><a class=\\\"!dt-text-black hover:!dt-text-black\\\" title=\\\"Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2\\\" href=\\\"https://dantri.com.vn/the-gioi/ty-phu-musk-mien-phi-internet-starlink-tai-venezuela-den-dau-thang-2-20260104172818185.htm\\\">Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2</a></h3>\\n</article>\\n</aside>\\n<p>&Ocirc;ng Trump cho biết Mỹ sẽ &ldquo;điều h&agrave;nh&rdquo; Venezuela trong giai đoạn ngay sau khi &ocirc;ng Maduro bị bắt, nhưng kh&ocirc;ng đưa ra chi tiết về c&aacute;ch thức điều h&agrave;nh hay thời gian k&eacute;o d&agrave;i bao l&acirc;u.</p>\\n<p>Tổng thống Trump đ&atilde; l&agrave;m r&otilde; tuy&ecirc;n bố tr&ecirc;n trong cuộc phỏng vấn với b&aacute;o New York Post. &Ocirc;ng cho biết Mỹ sẽ kh&ocirc;ng điều qu&acirc;n tới Venezuela nếu Ph&oacute; Tổng thống Delcy Rodriguez &ldquo;l&agrave;m theo những g&igrave; ch&uacute;ng t&ocirc;i muốn&rdquo;.</p>\\n<p>&Ocirc;ng Trump để ngỏ khả năng Mỹ sẽ triển khai qu&acirc;n đội tới Venezuela để bảo vệ c&aacute;c nguồn t&agrave;i nguy&ecirc;n dầu mỏ, đồng thời n&oacute;i rằng nguồn doanh thu n&agrave;y sẽ được d&ugrave;ng để bồi thường cho người d&acirc;n Venezuela v&agrave; cho Mỹ về những thiệt hại ph&aacute;t sinh trong thời kỳ cầm quyền của &ocirc;ng Maduro.</p>\\n<p>&Ocirc;ng Trump cũng cho biết &ocirc;ng dự định cho ph&eacute;p c&aacute;c c&ocirc;ng ty dầu mỏ của Mỹ tiếp quản cơ sở hạ tầng năng lượng của Venezuela. C&aacute;c quan chức cấp cao của Mỹ, bao gồm Ngoại trưởng Marco Rubio v&agrave; Bộ trưởng Chiến tranh Pete Hegseth, sẽ l&agrave;m việc c&ugrave;ng một &ldquo;nh&oacute;m&rdquo; để hỗ trợ việc điều h&agrave;nh Venezuela.</p>\\n</div>\", \"ja\": \"<h1 class=\\\"title-page detail\\\">Tiếng Nhật</h1>\\n<h1 class=\\\"title-page detail\\\">Nga tiết lộ t&igrave;nh h&igrave;nh ở Venezuela sau chiến dịch tấn c&ocirc;ng của Mỹ</h1>\\n<div class=\\\"author-wrap\\\">&nbsp;</div>\\n<div data-module=\\\"article-audio-new\\\" data-article-id=\\\"20260104180808480\\\" data-vast-url=\\\"https://pubads.g.doubleclick.net/gampad/ads?iu=/21899300285/dtadnetwork/audio&amp;description_url=https%3A%2F%2Fdantri.com.vn%2Fthe-gioi%2Fnga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm&amp;tfcd=0&amp;npa=0&amp;ad_type=audio&amp;sz=1x1&amp;gdfp_req=1&amp;output=vast&amp;unviewed_position_start=1&amp;env=vp&amp;impl=s&amp;wta=1&amp;plcmt=2&amp;correlator=\\\">\\n<div id=\\\"article-audio\\\">\\n<div>\\n<div class=\\\"j82SeqF_gxPVzIvNth9w\\\">\\n<div class=\\\"ySrzD84SzXaFjeHOPSdl\\\">\\n<div class=\\\"odifykg1Hpy_xVPsO7bL\\\">\\n<div class=\\\"hPoPnm_sPRyVcwvbMcGw\\\">&nbsp;</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n<h2 class=\\\"singular-sapo\\\">(D&acirc;n tr&iacute;) - Đại sứ Nga cho biết t&igrave;nh h&igrave;nh ở Venezuela hiện vẫn nằm dưới sự kiểm so&aacute;t của ch&iacute;nh quyền sau cuộc kh&ocirc;ng k&iacute;ch của Mỹ.</h2>\\n<div class=\\\"singular-content\\\">\\n<figure class=\\\"image align-center\\\"><img class=\\\"entered loaded\\\" title=\\\"Nga tiết lộ t&igrave;nh h&igrave;nh ở Venezuela sau chiến dịch tấn c&ocirc;ng của Mỹ - 1\\\" src=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg\\\" srcset=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg 1x, https://cdnphoto.dantri.com.vn/nxqStk-M8qAStdJHh3h9ttEc880=/thumb_w/1360/2026/01/03/xe-bus-1767453244829.jpg 2x\\\" alt=\\\"Nga tiết lộ t&igrave;nh h&igrave;nh ở Venezuela sau chiến dịch tấn c&ocirc;ng của Mỹ - 1\\\" data-width=\\\"700\\\" data-height=\\\"467\\\" data-original=\\\"https://cdnphoto.dantri.com.vn/WDJ0h_XUblJHeVUgB0mMduHZh24=/2026/01/03/xe-bus-1767453244829.jpg\\\" data-photo-id=\\\"3831271\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-image\\\" data-content-piece=\\\"article-content-image_3831271\\\" data-content-target=\\\"/the-gioi/nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm\\\" data-src=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg\\\" data-srcset=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg 1x, https://cdnphoto.dantri.com.vn/nxqStk-M8qAStdJHh3h9ttEc880=/thumb_w/1360/2026/01/03/xe-bus-1767453244829.jpg 2x\\\" data-ll-status=\\\"loaded\\\">\\n<figcaption>\\n<p>C&aacute;c phương tiện bị ph&aacute; hủy tại căn cứ kh&ocirc;ng qu&acirc;n La Carlota ở Caracas, Venezuela ng&agrave;y 3/1 (Ảnh: Reuters).</p>\\n</figcaption>\\n</figure>\\n<p>Đại sứ Nga tại Venezuela Sergey Melik-Bagdasarov n&oacute;i với h&atilde;ng th&ocirc;ng tấn TASS rằng, t&igrave;nh h&igrave;nh tại thủ đ&ocirc; Caracas của Venezuela hiện y&ecirc;n tĩnh v&agrave; vẫn nằm dưới sự kiểm so&aacute;t của ch&iacute;nh quyền sau cuộc kh&ocirc;ng k&iacute;ch của Mỹ.</p>\\n<p>\\\"T&igrave;nh h&igrave;nh ở Caracas hiện y&ecirc;n tĩnh v&agrave; ho&agrave;n to&agrave;n được ch&iacute;nh quyền kiểm so&aacute;t. Tuy nhi&ecirc;n, rất &iacute;t người ra đường, điều n&agrave;y thường &iacute;t xảy ra v&agrave;o ng&agrave;y cuối tuần&rdquo;, &ocirc;ng Melik-Bagdasarov cho biết h&ocirc;m 4/1.</p>\\n<p>&ldquo;R&otilde; r&agrave;ng, điều n&agrave;y kh&ocirc;ng chỉ được l&yacute; giải bởi t&acirc;m l&yacute; b&agrave;ng ho&agrave;ng sau vụ tấn c&ocirc;ng đ&ecirc;m qua, khiến người d&acirc;n vẫn c&ograve;n chịu ảnh hưởng, m&agrave; c&ograve;n bởi sự quan t&acirc;m của họ đến những&nbsp;<a href=\\\"https://dantri.com.vn/\\\" data-auto-link-id=\\\"5fd3362e5333a60018f3a1de\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-autolink\\\" data-content-piece=\\\"article-content-autolink_5fd3362e5333a60018f3a1de\\\" data-content-target=\\\"/the-gioi/nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm\\\">tin tức</a>&nbsp;đ&aacute;ng b&aacute;o động\\\", &ocirc;ng n&oacute;i, đồng thời cho biết Đại sứ qu&aacute;n Nga v&agrave; c&aacute;c ph&aacute;i đo&agrave;n ngoại giao kh&aacute;c của Nga tại Venezuela kh&ocirc;ng bị thiệt hại trong vụ tấn c&ocirc;ng của Mỹ.</p>\\n<p>Theo nh&agrave; ngoại giao Nga, kh&ocirc;ng c&oacute; c&ocirc;ng d&acirc;n Nga thiệt mạng hoặc bị thương trong cuộc kh&ocirc;ng k&iacute;ch của Mỹ v&agrave;o Venezuela v&agrave; Nga &ldquo;tiếp tục theo d&otilde;i t&igrave;nh h&igrave;nh&rdquo;.</p>\\n<p>\\\"Đại sứ qu&aacute;n đang l&agrave;m việc suốt ng&agrave;y đ&ecirc;m v&agrave; duy tr&igrave; li&ecirc;n lạc với Moscow, ch&iacute;nh phủ v&agrave; c&aacute;c cơ quan thực thi ph&aacute;p luật cũng đang phối hợp hoạt động. C&aacute;c biện ph&aacute;p an ninh đ&atilde; được tăng cường&rdquo;, Đại sứ Melik-Bagdasarov n&oacute;i th&ecirc;m.</p>\\n<p>Theo nh&agrave; ngoại giao Nga, Đại sứ qu&aacute;n Nga đ&atilde; nhận được nhiều cuộc gọi từ c&ocirc;ng d&acirc;n Nga đang sinh sống tại Venezuela v&agrave; từ người th&acirc;n của họ.</p>\\n<p>\\\"Ch&uacute;ng t&ocirc;i k&ecirc;u gọi người d&acirc;n kh&ocirc;ng n&ecirc;n hoảng loạn, tr&aacute;nh đến những nơi đ&ocirc;ng người, cũng như tr&aacute;nh ở gần c&aacute;c cơ sở qu&acirc;n sự, cơ sở năng lượng v&agrave; cơ sở truyền th&ocirc;ng, những nơi c&oacute; thể trở th&agrave;nh mục ti&ecirc;u trong trường hợp xảy ra c&aacute;c cuộc tấn c&ocirc;ng tiếp theo. Cuộc tấn c&ocirc;ng đ&ecirc;m qua đ&atilde; chứng minh rằng Mỹ biết ch&iacute;nh x&aacute;c vị tr&iacute; cần tấn c&ocirc;ng v&agrave; muốn ngăn chặn thương vong nặng nề cho d&acirc;n thường&rdquo;, Đại sứ Nga n&ecirc;u r&otilde;.</p>\\n<p>Ng&agrave;y 3/1, Ngoại trưởng Venezuela Yvan Gil Pinto x&aacute;c nhận Mỹ đ&atilde; tấn c&ocirc;ng c&aacute;c cơ sở d&acirc;n sự v&agrave;&nbsp;<a href=\\\"https://dantri.com.vn/the-gioi/quan-su.htm\\\" data-auto-link-id=\\\"6137992efb044100119a147e\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-autolink\\\" data-content-piece=\\\"article-content-autolink_6137992efb044100119a147e\\\" data-content-target=\\\"/the-gioi/nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm\\\">qu&acirc;n sự</a>&nbsp;ở Caracas. &Ocirc;ng l&ecirc;n &aacute;n cuộc kh&ocirc;ng k&iacute;ch của Washington l&agrave; h&agrave;nh động g&acirc;y hấn qu&acirc;n sự.</p>\\n<p>T&igrave;nh trạng khẩn cấp đ&atilde; được ban bố ở Venezuela. Tổng thống Mỹ Donald Trump đ&atilde; x&aacute;c nhận vụ tấn c&ocirc;ng v&agrave;o Venezuela. Theo nh&agrave; l&atilde;nh đạo Mỹ, Tổng thống Venezuela Nicolas Maduro v&agrave; vợ đ&atilde; bị bắt giữ v&agrave; đưa ra khỏi đất nước.</p>\\n<aside data-module=\\\"related-article-in-content\\\" data-id=\\\"20260104163820305\\\" data-index=\\\"0\\\">\\n<article class=\\\"dt-float-right dt-ml-5 dt-mb-5 dt-p-5 dt-bg-[#F3F6F6] dt-border-y-2 dt-border-y-[#FF8F2C] dt-flex dt-flex-col dt-gap-3 dt-relative dt-z-[1]\\\" data-track-content=\\\"true\\\" data-content-name=\\\"article-related-box\\\" data-content-piece=\\\"article-related-box-position_01\\\" data-content-target=\\\"/the-gioi/tong-thong-trump-lam-ro-tuyen-bo-dieu-hanh-venezuela-sau-cuoc-khong-kich-20260104163820305.htm\\\">\\n<div class=\\\"dt-flex dt-gap-[5px] dt-items-center dt-font-inter dt-text-common-sub dt-font-semibold dt-text-xs dt-leading-5\\\">TIN LI&Ecirc;N QUAN</div>\\n<h3 class=\\\"!dt-font-inter !dt-font-semibold !dt-text-base !dt-leading-22px xl:!dt-text-lg xl:!dt-leading-26px\\\"><a class=\\\"!dt-text-black hover:!dt-text-black\\\" title=\\\"Tổng thống Trump l&agrave;m r&otilde; tuy&ecirc;n bố &ldquo;điều h&agrave;nh Venezuela&rdquo; sau cuộc kh&ocirc;ng k&iacute;ch\\\" href=\\\"https://dantri.com.vn/the-gioi/tong-thong-trump-lam-ro-tuyen-bo-dieu-hanh-venezuela-sau-cuoc-khong-kich-20260104163820305.htm\\\">Tổng thống Trump l&agrave;m r&otilde; tuy&ecirc;n bố &ldquo;điều h&agrave;nh Venezuela&rdquo; sau cuộc kh&ocirc;ng k&iacute;ch</a></h3>\\n</article>\\n</aside>\\n<p>Bộ Ngoại giao Nga b&agrave;y tỏ quan ngại s&acirc;u sắc về h&agrave;nh động qu&acirc;n sự của Mỹ đối với Venezuela v&agrave; l&ecirc;n &aacute;n mạnh mẽ cuộc tấn c&ocirc;ng n&agrave;y. Trong t&igrave;nh h&igrave;nh n&agrave;y, Nga cho rằng điều cần thiết tr&ecirc;n hết l&agrave; ngăn chặn sự leo thang hơn nữa v&agrave; tập trung v&agrave;o việc t&igrave;m kiếm giải ph&aacute;p th&ocirc;ng qua đối thoại. Bộ Ngoại giao Nga y&ecirc;u cầu Mỹ ngay lập tức trả tự do cho Tổng thống Maduro v&agrave; vợ &ocirc;ng.</p>\\n<p>Bộ Ngoại giao Nga đ&atilde; l&ecirc;n &aacute;n h&agrave;nh động bắt giữ của Mỹ, đồng thời nhấn mạnh bất cứ l&yacute; do n&agrave;o biện minh cho những h&agrave;nh động đ&oacute; l&agrave; &ldquo;kh&ocirc;ng thể chấp nhận được&rdquo;. Theo Bộ Ngoại giao Nga, \\\"việc t&ocirc;n trọng chủ quyền l&agrave; một nguy&ecirc;n tắc then chốt của luật ph&aacute;p quốc tế\\\".</p>\\n<p>V&agrave;o tối 3/1, T&ograve;a &aacute;n Tối cao Venezuela đ&atilde; chỉ định Ph&oacute; Tổng thống Rodriguez trở th&agrave;nh l&atilde;nh đạo l&acirc;m thời của Venezuela.</p>\\n<p>T&ograve;a &aacute;n tối cao Venezuela đ&atilde; ph&aacute;n quyết rằng b&agrave; Rodriguez sẽ &ldquo;đảm nhiệm v&agrave; thực hiện, với tư c&aacute;ch l&agrave; người tạm quyền, tất cả nhiệm vụ v&agrave; quyền hạn vốn c&oacute; của Tổng thống&hellip; để đảm bảo t&iacute;nh li&ecirc;n tục của ch&iacute;nh quyền v&agrave; quốc ph&ograve;ng to&agrave;n diện của quốc gia&rdquo;.</p>\\n<p><strong>Kế hoạch của Mỹ sau chiến dịch kh&ocirc;ng k&iacute;ch</strong></p>\\n<p>Trong cuộc họp b&aacute;o sau chiến dịch kh&ocirc;ng k&iacute;ch Venezuela, Tổng thống Mỹ Donald Trump đ&atilde; n&ecirc;u một số kịch bản mới đối với quốc gia Nam Mỹ.</p>\\n<aside data-module=\\\"related-article-in-content\\\" data-id=\\\"20260104172818185\\\" data-index=\\\"1\\\">\\n<article class=\\\"dt-float-right dt-ml-5 dt-mb-5 dt-p-5 dt-bg-[#F3F6F6] dt-border-y-2 dt-border-y-[#FF8F2C] dt-flex dt-flex-col dt-gap-3 dt-relative dt-z-[1]\\\" data-track-content=\\\"true\\\" data-content-name=\\\"article-related-box\\\" data-content-piece=\\\"article-related-box-position_11\\\" data-content-target=\\\"/the-gioi/ty-phu-musk-mien-phi-internet-starlink-tai-venezuela-den-dau-thang-2-20260104172818185.htm\\\">\\n<div class=\\\"dt-flex dt-gap-[5px] dt-items-center dt-font-inter dt-text-common-sub dt-font-semibold dt-text-xs dt-leading-5\\\">TIN LI&Ecirc;N QUAN</div>\\n<a class=\\\"dt-w-full dt-cursor-pointer\\\" title=\\\"Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2\\\" href=\\\"https://dantri.com.vn/the-gioi/ty-phu-musk-mien-phi-internet-starlink-tai-venezuela-den-dau-thang-2-20260104172818185.htm\\\"><img class=\\\"dt-w-full dt-aspect-3/2\\\" src=\\\"https://cdnphoto.dantri.com.vn/hxUumo7USM5CU4FOqhflVLMW0HY=/thumb_w/768/2026/01/04/elonmusk-cropped-1767522375092.jpg\\\" alt=\\\"Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2\\\"></a>\\n<h3 class=\\\"!dt-font-inter !dt-font-semibold !dt-text-base !dt-leading-22px xl:!dt-text-lg xl:!dt-leading-26px\\\"><a class=\\\"!dt-text-black hover:!dt-text-black\\\" title=\\\"Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2\\\" href=\\\"https://dantri.com.vn/the-gioi/ty-phu-musk-mien-phi-internet-starlink-tai-venezuela-den-dau-thang-2-20260104172818185.htm\\\">Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2</a></h3>\\n</article>\\n</aside>\\n<p>&Ocirc;ng Trump cho biết Mỹ sẽ &ldquo;điều h&agrave;nh&rdquo; Venezuela trong giai đoạn ngay sau khi &ocirc;ng Maduro bị bắt, nhưng kh&ocirc;ng đưa ra chi tiết về c&aacute;ch thức điều h&agrave;nh hay thời gian k&eacute;o d&agrave;i bao l&acirc;u.</p>\\n<p>Tổng thống Trump đ&atilde; l&agrave;m r&otilde; tuy&ecirc;n bố tr&ecirc;n trong cuộc phỏng vấn với b&aacute;o New York Post. &Ocirc;ng cho biết Mỹ sẽ kh&ocirc;ng điều qu&acirc;n tới Venezuela nếu Ph&oacute; Tổng thống Delcy Rodriguez &ldquo;l&agrave;m theo những g&igrave; ch&uacute;ng t&ocirc;i muốn&rdquo;.</p>\\n<p>&Ocirc;ng Trump để ngỏ khả năng Mỹ sẽ triển khai qu&acirc;n đội tới Venezuela để bảo vệ c&aacute;c nguồn t&agrave;i nguy&ecirc;n dầu mỏ, đồng thời n&oacute;i rằng nguồn doanh thu n&agrave;y sẽ được d&ugrave;ng để bồi thường cho người d&acirc;n Venezuela v&agrave; cho Mỹ về những thiệt hại ph&aacute;t sinh trong thời kỳ cầm quyền của &ocirc;ng Maduro.</p>\\n<p>&Ocirc;ng Trump cũng cho biết &ocirc;ng dự định cho ph&eacute;p c&aacute;c c&ocirc;ng ty dầu mỏ của Mỹ tiếp quản cơ sở hạ tầng năng lượng của Venezuela. C&aacute;c quan chức cấp cao của Mỹ, bao gồm Ngoại trưởng Marco Rubio v&agrave; Bộ trưởng Chiến tranh Pete Hegseth, sẽ l&agrave;m việc c&ugrave;ng một &ldquo;nh&oacute;m&rdquo; để hỗ trợ việc điều h&agrave;nh Venezuela.</p>\\n</div>\", \"vi\": \"<h1 class=\\\"title-page detail\\\">Nga tiết lộ t&igrave;nh h&igrave;nh ở Venezuela sau chiến dịch tấn c&ocirc;ng của Mỹ</h1>\\n<div class=\\\"author-wrap\\\">&nbsp;</div>\\n<div data-module=\\\"article-audio-new\\\" data-article-id=\\\"20260104180808480\\\" data-vast-url=\\\"https://pubads.g.doubleclick.net/gampad/ads?iu=/21899300285/dtadnetwork/audio&amp;description_url=https%3A%2F%2Fdantri.com.vn%2Fthe-gioi%2Fnga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm&amp;tfcd=0&amp;npa=0&amp;ad_type=audio&amp;sz=1x1&amp;gdfp_req=1&amp;output=vast&amp;unviewed_position_start=1&amp;env=vp&amp;impl=s&amp;wta=1&amp;plcmt=2&amp;correlator=\\\">\\n<div id=\\\"article-audio\\\">\\n<div>\\n<div class=\\\"j82SeqF_gxPVzIvNth9w\\\">\\n<div class=\\\"ySrzD84SzXaFjeHOPSdl\\\">\\n<div class=\\\"odifykg1Hpy_xVPsO7bL\\\">\\n<div class=\\\"hPoPnm_sPRyVcwvbMcGw\\\">&nbsp;</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n</div>\\n<h2 class=\\\"singular-sapo\\\">(D&acirc;n tr&iacute;) - Đại sứ Nga cho biết t&igrave;nh h&igrave;nh ở Venezuela hiện vẫn nằm dưới sự kiểm so&aacute;t của ch&iacute;nh quyền sau cuộc kh&ocirc;ng k&iacute;ch của Mỹ.</h2>\\n<div class=\\\"singular-content\\\">\\n<figure class=\\\"image align-center\\\"><img class=\\\"entered loaded\\\" title=\\\"Nga tiết lộ t&igrave;nh h&igrave;nh ở Venezuela sau chiến dịch tấn c&ocirc;ng của Mỹ - 1\\\" src=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg\\\" srcset=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg 1x, https://cdnphoto.dantri.com.vn/nxqStk-M8qAStdJHh3h9ttEc880=/thumb_w/1360/2026/01/03/xe-bus-1767453244829.jpg 2x\\\" alt=\\\"Nga tiết lộ t&igrave;nh h&igrave;nh ở Venezuela sau chiến dịch tấn c&ocirc;ng của Mỹ - 1\\\" data-width=\\\"700\\\" data-height=\\\"467\\\" data-original=\\\"https://cdnphoto.dantri.com.vn/WDJ0h_XUblJHeVUgB0mMduHZh24=/2026/01/03/xe-bus-1767453244829.jpg\\\" data-photo-id=\\\"3831271\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-image\\\" data-content-piece=\\\"article-content-image_3831271\\\" data-content-target=\\\"/the-gioi/nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm\\\" data-src=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg\\\" data-srcset=\\\"https://cdnphoto.dantri.com.vn/ZnU7TXGwpgLfI9Fa_pl_kvk_jjY=/thumb_w/1020/2026/01/03/xe-bus-1767453244829.jpg 1x, https://cdnphoto.dantri.com.vn/nxqStk-M8qAStdJHh3h9ttEc880=/thumb_w/1360/2026/01/03/xe-bus-1767453244829.jpg 2x\\\" data-ll-status=\\\"loaded\\\">\\n<figcaption>\\n<p>C&aacute;c phương tiện bị ph&aacute; hủy tại căn cứ kh&ocirc;ng qu&acirc;n La Carlota ở Caracas, Venezuela ng&agrave;y 3/1 (Ảnh: Reuters).</p>\\n</figcaption>\\n</figure>\\n<p>Đại sứ Nga tại Venezuela Sergey Melik-Bagdasarov n&oacute;i với h&atilde;ng th&ocirc;ng tấn TASS rằng, t&igrave;nh h&igrave;nh tại thủ đ&ocirc; Caracas của Venezuela hiện y&ecirc;n tĩnh v&agrave; vẫn nằm dưới sự kiểm so&aacute;t của ch&iacute;nh quyền sau cuộc kh&ocirc;ng k&iacute;ch của Mỹ.</p>\\n<p>\\\"T&igrave;nh h&igrave;nh ở Caracas hiện y&ecirc;n tĩnh v&agrave; ho&agrave;n to&agrave;n được ch&iacute;nh quyền kiểm so&aacute;t. Tuy nhi&ecirc;n, rất &iacute;t người ra đường, điều n&agrave;y thường &iacute;t xảy ra v&agrave;o ng&agrave;y cuối tuần&rdquo;, &ocirc;ng Melik-Bagdasarov cho biết h&ocirc;m 4/1.</p>\\n<p>&ldquo;R&otilde; r&agrave;ng, điều n&agrave;y kh&ocirc;ng chỉ được l&yacute; giải bởi t&acirc;m l&yacute; b&agrave;ng ho&agrave;ng sau vụ tấn c&ocirc;ng đ&ecirc;m qua, khiến người d&acirc;n vẫn c&ograve;n chịu ảnh hưởng, m&agrave; c&ograve;n bởi sự quan t&acirc;m của họ đến những&nbsp;<a href=\\\"https://dantri.com.vn/\\\" data-auto-link-id=\\\"5fd3362e5333a60018f3a1de\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-autolink\\\" data-content-piece=\\\"article-content-autolink_5fd3362e5333a60018f3a1de\\\" data-content-target=\\\"/the-gioi/nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm\\\">tin tức</a>&nbsp;đ&aacute;ng b&aacute;o động\\\", &ocirc;ng n&oacute;i, đồng thời cho biết Đại sứ qu&aacute;n Nga v&agrave; c&aacute;c ph&aacute;i đo&agrave;n ngoại giao kh&aacute;c của Nga tại Venezuela kh&ocirc;ng bị thiệt hại trong vụ tấn c&ocirc;ng của Mỹ.</p>\\n<p>Theo nh&agrave; ngoại giao Nga, kh&ocirc;ng c&oacute; c&ocirc;ng d&acirc;n Nga thiệt mạng hoặc bị thương trong cuộc kh&ocirc;ng k&iacute;ch của Mỹ v&agrave;o Venezuela v&agrave; Nga &ldquo;tiếp tục theo d&otilde;i t&igrave;nh h&igrave;nh&rdquo;.</p>\\n<p>\\\"Đại sứ qu&aacute;n đang l&agrave;m việc suốt ng&agrave;y đ&ecirc;m v&agrave; duy tr&igrave; li&ecirc;n lạc với Moscow, ch&iacute;nh phủ v&agrave; c&aacute;c cơ quan thực thi ph&aacute;p luật cũng đang phối hợp hoạt động. C&aacute;c biện ph&aacute;p an ninh đ&atilde; được tăng cường&rdquo;, Đại sứ Melik-Bagdasarov n&oacute;i th&ecirc;m.</p>\\n<p>Theo nh&agrave; ngoại giao Nga, Đại sứ qu&aacute;n Nga đ&atilde; nhận được nhiều cuộc gọi từ c&ocirc;ng d&acirc;n Nga đang sinh sống tại Venezuela v&agrave; từ người th&acirc;n của họ.</p>\\n<p>\\\"Ch&uacute;ng t&ocirc;i k&ecirc;u gọi người d&acirc;n kh&ocirc;ng n&ecirc;n hoảng loạn, tr&aacute;nh đến những nơi đ&ocirc;ng người, cũng như tr&aacute;nh ở gần c&aacute;c cơ sở qu&acirc;n sự, cơ sở năng lượng v&agrave; cơ sở truyền th&ocirc;ng, những nơi c&oacute; thể trở th&agrave;nh mục ti&ecirc;u trong trường hợp xảy ra c&aacute;c cuộc tấn c&ocirc;ng tiếp theo. Cuộc tấn c&ocirc;ng đ&ecirc;m qua đ&atilde; chứng minh rằng Mỹ biết ch&iacute;nh x&aacute;c vị tr&iacute; cần tấn c&ocirc;ng v&agrave; muốn ngăn chặn thương vong nặng nề cho d&acirc;n thường&rdquo;, Đại sứ Nga n&ecirc;u r&otilde;.</p>\\n<p>Ng&agrave;y 3/1, Ngoại trưởng Venezuela Yvan Gil Pinto x&aacute;c nhận Mỹ đ&atilde; tấn c&ocirc;ng c&aacute;c cơ sở d&acirc;n sự v&agrave;&nbsp;<a href=\\\"https://dantri.com.vn/the-gioi/quan-su.htm\\\" data-auto-link-id=\\\"6137992efb044100119a147e\\\" data-track-content=\\\"\\\" data-content-name=\\\"article-content-autolink\\\" data-content-piece=\\\"article-content-autolink_6137992efb044100119a147e\\\" data-content-target=\\\"/the-gioi/nga-tiet-lo-tinh-hinh-o-venezuela-sau-chien-dich-tan-cong-cua-my-20260104180808480.htm\\\">qu&acirc;n sự</a>&nbsp;ở Caracas. &Ocirc;ng l&ecirc;n &aacute;n cuộc kh&ocirc;ng k&iacute;ch của Washington l&agrave; h&agrave;nh động g&acirc;y hấn qu&acirc;n sự.</p>\\n<p>T&igrave;nh trạng khẩn cấp đ&atilde; được ban bố ở Venezuela. Tổng thống Mỹ Donald Trump đ&atilde; x&aacute;c nhận vụ tấn c&ocirc;ng v&agrave;o Venezuela. Theo nh&agrave; l&atilde;nh đạo Mỹ, Tổng thống Venezuela Nicolas Maduro v&agrave; vợ đ&atilde; bị bắt giữ v&agrave; đưa ra khỏi đất nước.</p>\\n<aside data-module=\\\"related-article-in-content\\\" data-id=\\\"20260104163820305\\\" data-index=\\\"0\\\">\\n<article class=\\\"dt-float-right dt-ml-5 dt-mb-5 dt-p-5 dt-bg-[#F3F6F6] dt-border-y-2 dt-border-y-[#FF8F2C] dt-flex dt-flex-col dt-gap-3 dt-relative dt-z-[1]\\\" data-track-content=\\\"true\\\" data-content-name=\\\"article-related-box\\\" data-content-piece=\\\"article-related-box-position_01\\\" data-content-target=\\\"/the-gioi/tong-thong-trump-lam-ro-tuyen-bo-dieu-hanh-venezuela-sau-cuoc-khong-kich-20260104163820305.htm\\\">\\n<div class=\\\"dt-flex dt-gap-[5px] dt-items-center dt-font-inter dt-text-common-sub dt-font-semibold dt-text-xs dt-leading-5\\\">TIN LI&Ecirc;N QUAN</div>\\n<h3 class=\\\"!dt-font-inter !dt-font-semibold !dt-text-base !dt-leading-22px xl:!dt-text-lg xl:!dt-leading-26px\\\"><a class=\\\"!dt-text-black hover:!dt-text-black\\\" title=\\\"Tổng thống Trump l&agrave;m r&otilde; tuy&ecirc;n bố &ldquo;điều h&agrave;nh Venezuela&rdquo; sau cuộc kh&ocirc;ng k&iacute;ch\\\" href=\\\"https://dantri.com.vn/the-gioi/tong-thong-trump-lam-ro-tuyen-bo-dieu-hanh-venezuela-sau-cuoc-khong-kich-20260104163820305.htm\\\">Tổng thống Trump l&agrave;m r&otilde; tuy&ecirc;n bố &ldquo;điều h&agrave;nh Venezuela&rdquo; sau cuộc kh&ocirc;ng k&iacute;ch</a></h3>\\n</article>\\n</aside>\\n<p>Bộ Ngoại giao Nga b&agrave;y tỏ quan ngại s&acirc;u sắc về h&agrave;nh động qu&acirc;n sự của Mỹ đối với Venezuela v&agrave; l&ecirc;n &aacute;n mạnh mẽ cuộc tấn c&ocirc;ng n&agrave;y. Trong t&igrave;nh h&igrave;nh n&agrave;y, Nga cho rằng điều cần thiết tr&ecirc;n hết l&agrave; ngăn chặn sự leo thang hơn nữa v&agrave; tập trung v&agrave;o việc t&igrave;m kiếm giải ph&aacute;p th&ocirc;ng qua đối thoại. Bộ Ngoại giao Nga y&ecirc;u cầu Mỹ ngay lập tức trả tự do cho Tổng thống Maduro v&agrave; vợ &ocirc;ng.</p>\\n<p>Bộ Ngoại giao Nga đ&atilde; l&ecirc;n &aacute;n h&agrave;nh động bắt giữ của Mỹ, đồng thời nhấn mạnh bất cứ l&yacute; do n&agrave;o biện minh cho những h&agrave;nh động đ&oacute; l&agrave; &ldquo;kh&ocirc;ng thể chấp nhận được&rdquo;. Theo Bộ Ngoại giao Nga, \\\"việc t&ocirc;n trọng chủ quyền l&agrave; một nguy&ecirc;n tắc then chốt của luật ph&aacute;p quốc tế\\\".</p>\\n<p>V&agrave;o tối 3/1, T&ograve;a &aacute;n Tối cao Venezuela đ&atilde; chỉ định Ph&oacute; Tổng thống Rodriguez trở th&agrave;nh l&atilde;nh đạo l&acirc;m thời của Venezuela.</p>\\n<p>T&ograve;a &aacute;n tối cao Venezuela đ&atilde; ph&aacute;n quyết rằng b&agrave; Rodriguez sẽ &ldquo;đảm nhiệm v&agrave; thực hiện, với tư c&aacute;ch l&agrave; người tạm quyền, tất cả nhiệm vụ v&agrave; quyền hạn vốn c&oacute; của Tổng thống&hellip; để đảm bảo t&iacute;nh li&ecirc;n tục của ch&iacute;nh quyền v&agrave; quốc ph&ograve;ng to&agrave;n diện của quốc gia&rdquo;.</p>\\n<p><strong>Kế hoạch của Mỹ sau chiến dịch kh&ocirc;ng k&iacute;ch</strong></p>\\n<p>Trong cuộc họp b&aacute;o sau chiến dịch kh&ocirc;ng k&iacute;ch Venezuela, Tổng thống Mỹ Donald Trump đ&atilde; n&ecirc;u một số kịch bản mới đối với quốc gia Nam Mỹ.</p>\\n<aside data-module=\\\"related-article-in-content\\\" data-id=\\\"20260104172818185\\\" data-index=\\\"1\\\">\\n<article class=\\\"dt-float-right dt-ml-5 dt-mb-5 dt-p-5 dt-bg-[#F3F6F6] dt-border-y-2 dt-border-y-[#FF8F2C] dt-flex dt-flex-col dt-gap-3 dt-relative dt-z-[1]\\\" data-track-content=\\\"true\\\" data-content-name=\\\"article-related-box\\\" data-content-piece=\\\"article-related-box-position_11\\\" data-content-target=\\\"/the-gioi/ty-phu-musk-mien-phi-internet-starlink-tai-venezuela-den-dau-thang-2-20260104172818185.htm\\\">\\n<div class=\\\"dt-flex dt-gap-[5px] dt-items-center dt-font-inter dt-text-common-sub dt-font-semibold dt-text-xs dt-leading-5\\\">TIN LI&Ecirc;N QUAN</div>\\n<a class=\\\"dt-w-full dt-cursor-pointer\\\" title=\\\"Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2\\\" href=\\\"https://dantri.com.vn/the-gioi/ty-phu-musk-mien-phi-internet-starlink-tai-venezuela-den-dau-thang-2-20260104172818185.htm\\\"><img class=\\\"dt-w-full dt-aspect-3/2\\\" src=\\\"https://cdnphoto.dantri.com.vn/hxUumo7USM5CU4FOqhflVLMW0HY=/thumb_w/768/2026/01/04/elonmusk-cropped-1767522375092.jpg\\\" alt=\\\"Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2\\\"></a>\\n<h3 class=\\\"!dt-font-inter !dt-font-semibold !dt-text-base !dt-leading-22px xl:!dt-text-lg xl:!dt-leading-26px\\\"><a class=\\\"!dt-text-black hover:!dt-text-black\\\" title=\\\"Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2\\\" href=\\\"https://dantri.com.vn/the-gioi/ty-phu-musk-mien-phi-internet-starlink-tai-venezuela-den-dau-thang-2-20260104172818185.htm\\\">Tỷ ph&uacute; Musk miễn ph&iacute; Internet Starlink tại Venezuela đến đầu th&aacute;ng 2</a></h3>\\n</article>\\n</aside>\\n<p>&Ocirc;ng Trump cho biết Mỹ sẽ &ldquo;điều h&agrave;nh&rdquo; Venezuela trong giai đoạn ngay sau khi &ocirc;ng Maduro bị bắt, nhưng kh&ocirc;ng đưa ra chi tiết về c&aacute;ch thức điều h&agrave;nh hay thời gian k&eacute;o d&agrave;i bao l&acirc;u.</p>\\n<p>Tổng thống Trump đ&atilde; l&agrave;m r&otilde; tuy&ecirc;n bố tr&ecirc;n trong cuộc phỏng vấn với b&aacute;o New York Post. &Ocirc;ng cho biết Mỹ sẽ kh&ocirc;ng điều qu&acirc;n tới Venezuela nếu Ph&oacute; Tổng thống Delcy Rodriguez &ldquo;l&agrave;m theo những g&igrave; ch&uacute;ng t&ocirc;i muốn&rdquo;.</p>\\n<p>&Ocirc;ng Trump để ngỏ khả năng Mỹ sẽ triển khai qu&acirc;n đội tới Venezuela để bảo vệ c&aacute;c nguồn t&agrave;i nguy&ecirc;n dầu mỏ, đồng thời n&oacute;i rằng nguồn doanh thu n&agrave;y sẽ được d&ugrave;ng để bồi thường cho người d&acirc;n Venezuela v&agrave; cho Mỹ về những thiệt hại ph&aacute;t sinh trong thời kỳ cầm quyền của &ocirc;ng Maduro.</p>\\n<p>&Ocirc;ng Trump cũng cho biết &ocirc;ng dự định cho ph&eacute;p c&aacute;c c&ocirc;ng ty dầu mỏ của Mỹ tiếp quản cơ sở hạ tầng năng lượng của Venezuela. C&aacute;c quan chức cấp cao của Mỹ, bao gồm Ngoại trưởng Marco Rubio v&agrave; Bộ trưởng Chiến tranh Pete Hegseth, sẽ l&agrave;m việc c&ugrave;ng một &ldquo;nh&oacute;m&rdquo; để hỗ trợ việc điều h&agrave;nh Venezuela.</p>\\n</div>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-04 16:27:11','2026-01-09 04:01:59'),
(5,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Công ty TNHH Giải pháp Môi trường Xanh Bền Vững Nhật Việt\"}','cong-ty-tnhh-giai-phap-moi-truong-xanh-ben-vung-nhat-viet','[10]',10,NULL,'[]','[]','[]','[]',0,15,1,1,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>C&ocirc;ng ty TNHH Giải ph&aacute;p M&ocirc;i trường Xanh Bền Vững Nhật Việt l&agrave; doanh nghiệp li&ecirc;n doanh giữa Nhật Bản v&agrave; Việt Nam,<br>hoạt động trong lĩnh vực c&ocirc;ng nghệ sinh học m&ocirc;i trường, ứng dụng c&ocirc;ng nghệ BMW nhằm phục vụ t&aacute;i chế bền vững,<br>bảo vệ m&ocirc;i trường v&agrave; ph&aacute;t triển n&ocirc;ng nghiệp tuần ho&agrave;n tại Việt Nam.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"528\\\" data-end=\\\"600\\\">Giới thiệu C&ocirc;ng ty TNHH Giải ph&aacute;p M&ocirc;i trường Xanh Bền Vững Nhật Việt</h3>\\n<p data-start=\\\"602\\\" data-end=\\\"847\\\">C&ocirc;ng ty TNHH Giải ph&aacute;p M&ocirc;i trường Xanh Bền Vững Nhật Việt l&agrave; doanh nghiệp li&ecirc;n doanh giữa Nhật Bản v&agrave; Việt Nam, được th&agrave;nh lập với mục ti&ecirc;u kết hợp c&ocirc;ng nghệ sinh học ti&ecirc;n tiến từ Nhật Bản c&ugrave;ng tiềm năng ph&aacute;t triển n&ocirc;ng nghiệp xanh tại Việt Nam.</p>\\n<p data-start=\\\"849\\\" data-end=\\\"1120\\\">C&ocirc;ng ty hoạt động trong lĩnh vực c&ocirc;ng nghệ sinh học m&ocirc;i trường, tập trung v&agrave;o việc nghi&ecirc;n cứu, chuyển giao v&agrave; ứng dụng c&aacute;c giải ph&aacute;p c&ocirc;ng nghệ th&acirc;n thiện với m&ocirc;i trường, ph&ugrave; hợp với điều kiện tự nhi&ecirc;n, sản xuất n&ocirc;ng nghiệp, chăn nu&ocirc;i v&agrave; m&ocirc;i trường n&ocirc;ng th&ocirc;n tại Việt Nam.</p>\\n<h3 data-start=\\\"1122\\\" data-end=\\\"1148\\\">Tổng quan doanh nghiệp</h3>\\n<p data-start=\\\"1150\\\" data-end=\\\"1410\\\">Với định hướng ph&aacute;t triển bền vững, C&ocirc;ng ty TNHH Giải ph&aacute;p M&ocirc;i trường Xanh Bền Vững Nhật Việt kh&ocirc;ng chỉ cung cấp giải ph&aacute;p c&ocirc;ng nghệ m&agrave; c&ograve;n hướng tới việc x&acirc;y dựng m&ocirc; h&igrave;nh sản xuất tuần ho&agrave;n, gi&uacute;p tối ưu t&agrave;i nguy&ecirc;n, giảm thiểu chất thải v&agrave; bảo vệ hệ sinh th&aacute;i.</p>\\n<p data-start=\\\"1412\\\" data-end=\\\"1619\\\">Th&ocirc;ng qua m&ocirc; h&igrave;nh hợp t&aacute;c Nhật &ndash; Việt, c&ocirc;ng ty từng bước đưa c&aacute;c giải ph&aacute;p c&ocirc;ng nghệ sinh học ti&ecirc;n tiến v&agrave;o thực tiễn, g&oacute;p phần n&acirc;ng cao hiệu quả sản xuất n&ocirc;ng nghiệp v&agrave; cải thiện chất lượng m&ocirc;i trường sống.</p>\\n<h3 data-start=\\\"1621\\\" data-end=\\\"1663\\\">Nền tảng c&ocirc;ng nghệ v&agrave; tổ chức li&ecirc;n kết</h3>\\n<p data-start=\\\"1665\\\" data-end=\\\"1907\\\">C&ocirc;ng ty l&agrave; th&agrave;nh vi&ecirc;n của Hiệp hội C&ocirc;ng nghệ BMW Nhật Bản &ndash; tổ chức phi lợi nhuận được th&agrave;nh lập từ năm 1990, chuy&ecirc;n nghi&ecirc;n cứu, ph&aacute;t triển v&agrave; phổ biến c&ocirc;ng nghệ BMW trong lĩnh vực t&aacute;i chế bền vững, bảo vệ m&ocirc;i trường v&agrave; n&ocirc;ng nghiệp tuần ho&agrave;n.</p>\\n<p data-start=\\\"1909\\\" data-end=\\\"2195\\\">C&ocirc;ng nghệ BMW (Bacteria &ndash; Mineral &ndash; Water) được ph&aacute;t triển dựa tr&ecirc;n nguy&ecirc;n l&yacute; tuần ho&agrave;n tự nhi&ecirc;n, kết hợp vi sinh vật c&oacute; lợi v&agrave; kho&aacute;ng chất nhằm xử l&yacute; chất thải hữu cơ, cải thiện chất lượng nước v&agrave; đất, đồng thời t&aacute;i tạo v&agrave; t&aacute;i sử dụng t&agrave;i nguy&ecirc;n một c&aacute;ch an to&agrave;n, hiệu quả v&agrave; bền vững.</p>\\n<h3 data-start=\\\"2197\\\" data-end=\\\"2247\\\">Định hướng v&agrave; mục ti&ecirc;u ph&aacute;t triển tại Việt Nam</h3>\\n<p data-start=\\\"2249\\\" data-end=\\\"2476\\\">Mục ti&ecirc;u của c&ocirc;ng ty l&agrave; phổ cập v&agrave; hướng dẫn ứng dụng c&ocirc;ng nghệ BMW Nhật Bản để người d&acirc;n Việt Nam c&oacute; thể chủ động &aacute;p dụng trong sản xuất n&ocirc;ng nghiệp v&agrave; xử l&yacute; m&ocirc;i trường, đặc biệt tại khu vực n&ocirc;ng th&ocirc;n v&agrave; c&aacute;c m&ocirc; h&igrave;nh chăn nu&ocirc;i.</p>\\n<p data-start=\\\"2478\\\" data-end=\\\"2753\\\">B&ecirc;n cạnh việc chuyển giao c&ocirc;ng nghệ, c&ocirc;ng ty ch&uacute; trọng đến hoạt động đ&agrave;o tạo, hướng dẫn kỹ thuật v&agrave; đồng h&agrave;nh l&acirc;u d&agrave;i c&ugrave;ng người d&acirc;n, trang trại v&agrave; doanh nghiệp, hướng tới ph&aacute;t triển n&ocirc;ng nghiệp xanh, bảo vệ m&ocirc;i trường v&agrave; x&acirc;y dựng hệ sinh th&aacute;i sản xuất bền vững tại Việt Nam.</p>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:08:12','2026-01-09 04:05:08'),
(6,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Công Nghệ BMW\"}','cong-nghe-bmw','[11]',11,NULL,'[]','[]','[]','[]',0,38,0,0,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>C&ocirc;ng nghệ BMW l&agrave; c&ocirc;ng nghệ sinh học dựa tr&ecirc;n nguy&ecirc;n l&yacute; tuần ho&agrave;n tự nhi&ecirc;n, kết hợp vi sinh vật, kho&aacute;ng chất v&agrave; nước nhằm tận dụng hiệu quả chất hữu cơ trong m&ocirc;i trường. C&ocirc;ng nghệ n&agrave;y đ&atilde; được phổ biến từ năm 1990 v&agrave; hiện đang được ứng dụng rộng r&atilde;i tại Nhật Bản v&agrave; nhiều quốc gia tr&ecirc;n thế giới.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"547\\\" data-end=\\\"571\\\">C&ocirc;ng nghệ BMW l&agrave; g&igrave;?</h3>\\n<p data-start=\\\"573\\\" data-end=\\\"652\\\">BMW l&agrave; t&ecirc;n viết tắt của ba yếu tố cốt l&otilde;i trong hệ sinh th&aacute;i tự nhi&ecirc;n, bao gồm:</p>\\n<ul data-start=\\\"654\\\" data-end=\\\"743\\\">\\n<li data-start=\\\"654\\\" data-end=\\\"684\\\">\\n<p data-start=\\\"656\\\" data-end=\\\"684\\\"><strong data-start=\\\"656\\\" data-end=\\\"682\\\">B (Bacteria &ndash; vi sinh)</strong></p>\\n</li>\\n<li data-start=\\\"685\\\" data-end=\\\"718\\\">\\n<p data-start=\\\"687\\\" data-end=\\\"718\\\"><strong data-start=\\\"687\\\" data-end=\\\"716\\\">M (Mineral &ndash; kho&aacute;ng chất)</strong></p>\\n</li>\\n<li data-start=\\\"719\\\" data-end=\\\"743\\\">\\n<p data-start=\\\"721\\\" data-end=\\\"743\\\"><strong data-start=\\\"721\\\" data-end=\\\"741\\\">W (Water &ndash; nước)</strong></p>\\n</li>\\n</ul>\\n<p data-start=\\\"745\\\" data-end=\\\"909\\\">Ba yếu tố n&agrave;y kết hợp với nhau tạo n&ecirc;n nền tảng của c&ocirc;ng nghệ BMW, một c&ocirc;ng nghệ sinh học được ph&aacute;t triển dựa tr&ecirc;n nguy&ecirc;n l&yacute; tuần ho&agrave;n tự nhi&ecirc;n của m&ocirc;i trường sống.</p>\\n<h3 data-start=\\\"911\\\" data-end=\\\"952\\\">Nguy&ecirc;n l&yacute; hoạt động của c&ocirc;ng nghệ BMW</h3>\\n<p data-start=\\\"954\\\" data-end=\\\"1136\\\">C&ocirc;ng nghệ BMW được m&ocirc; phỏng theo hệ thống tuần ho&agrave;n của thế giới tự nhi&ecirc;n, trong đ&oacute; c&aacute;c chất hữu cơ từ đất, nước v&agrave; chất thải sinh học được tận dụng v&agrave; t&aacute;i sử dụng một c&aacute;ch hiệu quả.</p>\\n<p data-start=\\\"1138\\\" data-end=\\\"1398\\\">Th&ocirc;ng qua việc k&iacute;ch hoạt v&agrave; th&uacute;c đẩy hoạt động của c&aacute;c vi khuẩn (vi sinh vật) c&oacute; sẵn trong m&ocirc;i trường, c&ocirc;ng nghệ BMW gi&uacute;p ph&acirc;n giải chất hữu cơ, cải thiện chất lượng đất v&agrave; nước, đồng thời tạo ra một v&ograve;ng tuần ho&agrave;n sinh học bền vững, th&acirc;n thiện với m&ocirc;i trường.</p>\\n<h3 data-start=\\\"1400\\\" data-end=\\\"1446\\\">Qu&aacute; tr&igrave;nh ph&aacute;t triển v&agrave; ứng dụng thực tiễn</h3>\\n<p data-start=\\\"1448\\\" data-end=\\\"1646\\\">Từ năm 1990, c&ocirc;ng nghệ BMW đ&atilde; được phổ biến rộng r&atilde;i tại Nhật Bản v&agrave; được ứng dụng trong lĩnh vực n&ocirc;ng nghiệp hữu cơ, n&ocirc;ng nghiệp tuần ho&agrave;n tự nhi&ecirc;n cũng như tại c&aacute;c hợp t&aacute;c x&atilde; sản xuất n&ocirc;ng nghiệp.</p>\\n<p data-start=\\\"1648\\\" data-end=\\\"1896\\\">Nhờ t&iacute;nh hiệu quả, an to&agrave;n v&agrave; ph&ugrave; hợp với tự nhi&ecirc;n, c&ocirc;ng nghệ BMW ng&agrave;y c&agrave;ng được nh&acirc;n rộng v&agrave; sử dụng rộng r&atilde;i kh&ocirc;ng chỉ tại Nhật Bản m&agrave; c&ograve;n tại nhiều quốc gia tr&ecirc;n thế giới, g&oacute;p phần th&uacute;c đẩy m&ocirc; h&igrave;nh sản xuất bền vững v&agrave; bảo vệ m&ocirc;i trường l&acirc;u d&agrave;i.</p>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:17:36','2026-01-09 04:05:09'),
(7,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Hệ Thống Sản Xuất Nước Sinh Học\"}','he-thong-san-xuat-nuoc-sinh-hoc','[11]',16,NULL,'[]','[]','[]','[]',0,17,0,0,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>Hệ thống sản xuất nước sinh học BMW l&agrave; hệ thống đồng bộ sử dụng c&ocirc;ng nghệ Nhật Bản, được thiết kế để sản xuất nước hoạt t&iacute;nh sinh học đa năng. Hệ thống ứng dụng rộng r&atilde;i trong n&ocirc;ng nghiệp, xử l&yacute; m&ocirc;i trường v&agrave; đời sống, g&oacute;p phần t&aacute;i sử dụng t&agrave;i nguy&ecirc;n v&agrave; bảo vệ m&ocirc;i trường bền vững.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"550\\\" data-end=\\\"589\\\">Hệ thống sản xuất nước sinh học BMW</h3>\\n<p data-start=\\\"591\\\" data-end=\\\"881\\\">Hệ thống sản xuất nước sinh học l&agrave; hệ thống đồng bộ c&aacute;c trang thiết bị chuy&ecirc;n dụng, được thiết kế nhằm sản xuất nước hoạt t&iacute;nh sinh học đa năng BMW. Hệ thống sử dụng c&ocirc;ng nghệ Nhật Bản, kết hợp vật liệu inox chất lượng cao, đảm bảo độ bền, an to&agrave;n v&agrave; ph&ugrave; hợp cho qu&aacute; tr&igrave;nh vận h&agrave;nh l&acirc;u d&agrave;i.</p>\\n<p data-start=\\\"883\\\" data-end=\\\"1035\\\">Nước sinh học BMW được tạo ra từ hệ thống n&agrave;y c&oacute; t&iacute;nh ổn định cao, phục vụ nhiều mục đ&iacute;ch kh&aacute;c nhau trong n&ocirc;ng nghiệp, m&ocirc;i trường v&agrave; đời sống hằng ng&agrave;y.</p>\\n<h3 data-start=\\\"1037\\\" data-end=\\\"1067\\\">Th&ocirc;ng số kỹ thuật hệ thống</h3>\\n<p data-start=\\\"1069\\\" data-end=\\\"1161\\\">Hệ thống được thiết kế với cấu h&igrave;nh ti&ecirc;u chuẩn, đ&aacute;p ứng nhu cầu sản xuất v&agrave; sử dụng thực tế:</p>\\n<ul data-start=\\\"1163\\\" data-end=\\\"1419\\\">\\n<li data-start=\\\"1163\\\" data-end=\\\"1213\\\">\\n<p data-start=\\\"1165\\\" data-end=\\\"1213\\\">Hệ thống gồm <strong data-start=\\\"1178\\\" data-end=\\\"1187\\\">6 bồn</strong>, dung t&iacute;ch <strong data-start=\\\"1199\\\" data-end=\\\"1211\\\">6 m&sup3;/bồn</strong></p>\\n</li>\\n<li data-start=\\\"1214\\\" data-end=\\\"1279\\\">\\n<p data-start=\\\"1216\\\" data-end=\\\"1279\\\">K&iacute;ch thước mỗi bồn: <strong data-start=\\\"1236\\\" data-end=\\\"1277\\\">đường k&iacute;nh 2000 mm, chiều cao 2000 mm</strong></p>\\n</li>\\n<li data-start=\\\"1280\\\" data-end=\\\"1318\\\">\\n<p data-start=\\\"1282\\\" data-end=\\\"1318\\\">Vật liệu chế tạo: <strong data-start=\\\"1300\\\" data-end=\\\"1316\\\">Inox SUS 304</strong></p>\\n</li>\\n<li data-start=\\\"1319\\\" data-end=\\\"1356\\\">\\n<p data-start=\\\"1321\\\" data-end=\\\"1356\\\">Độ d&agrave;y mặt inox: <strong data-start=\\\"1338\\\" data-end=\\\"1354\\\">1,5 mm (&plusmn;5%)</strong></p>\\n</li>\\n<li data-start=\\\"1357\\\" data-end=\\\"1419\\\">\\n<p data-start=\\\"1359\\\" data-end=\\\"1419\\\">C&ocirc;ng suất sản xuất: <strong data-start=\\\"1379\\\" data-end=\\\"1419\\\">300 &ndash; 500 l&iacute;t nước sinh học mỗi ng&agrave;y</strong></p>\\n</li>\\n</ul>\\n<p data-start=\\\"1421\\\" data-end=\\\"1525\\\">Thiết kế n&agrave;y gi&uacute;p hệ thống vận h&agrave;nh ổn định, dễ bảo tr&igrave; v&agrave; ph&ugrave; hợp với nhiều m&ocirc; h&igrave;nh sản xuất kh&aacute;c nhau.</p>\\n<h3 data-start=\\\"1527\\\" data-end=\\\"1561\\\">Ứng dụng của nước sinh học BMW</h3>\\n<p data-start=\\\"1563\\\" data-end=\\\"1626\\\">Nước sinh học BMW được ứng dụng linh hoạt trong nhiều lĩnh vực:</p>\\n<p data-start=\\\"1628\\\" data-end=\\\"1842\\\"><strong data-start=\\\"1628\\\" data-end=\\\"1649\\\">Trong n&ocirc;ng nghiệp</strong><br data-start=\\\"1649\\\" data-end=\\\"1652\\\">Nước sinh học BMW được sử dụng trong trồng trọt, chăn nu&ocirc;i v&agrave; nu&ocirc;i trồng thủy hải sản, gi&uacute;p cải thiện m&ocirc;i trường đất v&agrave; nước, hỗ trợ qu&aacute; tr&igrave;nh sinh trưởng tự nhi&ecirc;n của c&acirc;y trồng v&agrave; vật nu&ocirc;i.</p>\\n<p data-start=\\\"1844\\\" data-end=\\\"2037\\\"><strong data-start=\\\"1844\\\" data-end=\\\"1870\\\">Trong xử l&yacute; m&ocirc;i trường</strong><br data-start=\\\"1870\\\" data-end=\\\"1873\\\">Hệ thống được ứng dụng trong xử l&yacute; nước thải, nước t&aacute;i chế v&agrave; r&aacute;c thải, g&oacute;p phần giảm &ocirc; nhiễm, t&aacute;i sử dụng t&agrave;i nguy&ecirc;n v&agrave; x&acirc;y dựng m&ocirc; h&igrave;nh xử l&yacute; m&ocirc;i trường bền vững.</p>\\n<p data-start=\\\"2039\\\" data-end=\\\"2265\\\"><strong data-start=\\\"2039\\\" data-end=\\\"2057\\\">Trong đời sống</strong><br data-start=\\\"2057\\\" data-end=\\\"2060\\\">Nước sinh học BMW c&ograve;n được sử dụng trong xử l&yacute; r&aacute;c thải sinh hoạt, chăm s&oacute;c th&uacute; cưng, khử m&ugrave;i, l&agrave;m sạch bể c&aacute;, trồng c&acirc;y, cắm hoa v&agrave; nhiều ứng dụng sinh hoạt kh&aacute;c, gi&uacute;p cải thiện m&ocirc;i trường sống hằng ng&agrave;y.</p>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:20:09','2026-01-09 03:59:43'),
(8,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Hệ Thống Cải Thiện Nước Uống Vật Nuôi\"}','he-thong-cai-thien-nuoc-uong-vat-nuoi','[11]',17,NULL,'[]','[]','[]','[]',0,10,1,1,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>Hệ thống cải thiện nước uống vật nu&ocirc;i l&agrave; hệ thống tuần ho&agrave;n sử dụng c&ocirc;ng nghệ Nhật Bản, gi&uacute;p n&acirc;ng cao chất lượng nguồn nước th&ocirc;ng qua lọc nước, bổ sung kho&aacute;ng chất tự nhi&ecirc;n v&agrave; vi sinh vật c&oacute; lợi. Hệ thống g&oacute;p phần cải thiện sức khỏe vật nu&ocirc;i, tăng hiệu quả chăn nu&ocirc;i v&agrave; giảm &ocirc; nhiễm m&ocirc;i trường chuồng trại.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"601\\\" data-end=\\\"642\\\">Hệ thống cải thiện nước uống vật nu&ocirc;i</h3>\\n<p data-start=\\\"644\\\" data-end=\\\"975\\\">Hệ thống cải thiện nước uống vật nu&ocirc;i l&agrave; hệ thống tuần ho&agrave;n ứng dụng c&ocirc;ng nghệ Nhật Bản, được thiết kế nhằm n&acirc;ng cao chất lượng nguồn nước uống cho vật nu&ocirc;i. Th&ocirc;ng qua qu&aacute; tr&igrave;nh lọc nước, bổ sung kho&aacute;ng chất tự nhi&ecirc;n v&agrave; c&aacute;c nguồn vi sinh vật c&oacute; lợi, hệ thống gi&uacute;p tạo ra nguồn nước sạch, ổn định v&agrave; an to&agrave;n cho qu&aacute; tr&igrave;nh chăn nu&ocirc;i.</p>\\n<p data-start=\\\"977\\\" data-end=\\\"1148\\\">Việc sử dụng nguồn nước được cải thiện kh&ocirc;ng chỉ g&oacute;p phần n&acirc;ng cao sức khỏe vật nu&ocirc;i m&agrave; c&ograve;n gi&uacute;p tối ưu hiệu quả sản xuất, hướng tới m&ocirc; h&igrave;nh chăn nu&ocirc;i an to&agrave;n v&agrave; bền vững.</p>\\n<h3 data-start=\\\"1150\\\" data-end=\\\"1180\\\">Th&ocirc;ng số kỹ thuật hệ thống</h3>\\n<p data-start=\\\"1182\\\" data-end=\\\"1265\\\">Hệ thống được thiết kế với cấu h&igrave;nh ph&ugrave; hợp cho nhiều m&ocirc; h&igrave;nh trang trại chăn nu&ocirc;i:</p>\\n<ul data-start=\\\"1267\\\" data-end=\\\"1508\\\">\\n<li data-start=\\\"1267\\\" data-end=\\\"1319\\\">\\n<p data-start=\\\"1269\\\" data-end=\\\"1319\\\">Hệ thống gồm <strong data-start=\\\"1282\\\" data-end=\\\"1291\\\">3 bồn</strong>, dung t&iacute;ch <strong data-start=\\\"1303\\\" data-end=\\\"1317\\\">2,5 m&sup3;/bồn</strong></p>\\n</li>\\n<li data-start=\\\"1320\\\" data-end=\\\"1385\\\">\\n<p data-start=\\\"1322\\\" data-end=\\\"1385\\\">K&iacute;ch thước mỗi bồn: <strong data-start=\\\"1342\\\" data-end=\\\"1383\\\">đường k&iacute;nh 1200 mm, chiều cao 2000 mm</strong></p>\\n</li>\\n<li data-start=\\\"1386\\\" data-end=\\\"1424\\\">\\n<p data-start=\\\"1388\\\" data-end=\\\"1424\\\">Vật liệu chế tạo: <strong data-start=\\\"1406\\\" data-end=\\\"1422\\\">Inox SUS 304</strong></p>\\n</li>\\n<li data-start=\\\"1425\\\" data-end=\\\"1462\\\">\\n<p data-start=\\\"1427\\\" data-end=\\\"1462\\\">Độ d&agrave;y mặt inox: <strong data-start=\\\"1444\\\" data-end=\\\"1460\\\">1,5 mm (&plusmn;5%)</strong></p>\\n</li>\\n<li data-start=\\\"1463\\\" data-end=\\\"1508\\\">\\n<p data-start=\\\"1465\\\" data-end=\\\"1508\\\">C&ocirc;ng suất xử l&yacute;: <strong data-start=\\\"1482\\\" data-end=\\\"1508\\\">3 &ndash; 5 m&sup3; nước mỗi ng&agrave;y</strong></p>\\n</li>\\n</ul>\\n<p data-start=\\\"1510\\\" data-end=\\\"1613\\\">Cấu h&igrave;nh n&agrave;y gi&uacute;p hệ thống vận h&agrave;nh ổn định, bền bỉ v&agrave; dễ d&agrave;ng bảo tr&igrave; trong qu&aacute; tr&igrave;nh sử dụng l&acirc;u d&agrave;i.</p>\\n<h3 data-start=\\\"1615\\\" data-end=\\\"1646\\\">T&aacute;c dụng đối với nguồn nước</h3>\\n<p data-start=\\\"1648\\\" data-end=\\\"1735\\\">Hệ thống cải thiện nước uống vật nu&ocirc;i mang lại nhiều lợi &iacute;ch cho chất lượng nguồn nước:</p>\\n<ul data-start=\\\"1737\\\" data-end=\\\"1870\\\">\\n<li data-start=\\\"1737\\\" data-end=\\\"1772\\\">\\n<p data-start=\\\"1739\\\" data-end=\\\"1772\\\">L&agrave;m sạch hơn nguồn nước đầu v&agrave;o</p>\\n</li>\\n<li data-start=\\\"1773\\\" data-end=\\\"1815\\\">\\n<p data-start=\\\"1775\\\" data-end=\\\"1815\\\">Bổ sung kho&aacute;ng chất tự nhi&ecirc;n cần thiết</p>\\n</li>\\n<li data-start=\\\"1816\\\" data-end=\\\"1870\\\">\\n<p data-start=\\\"1818\\\" data-end=\\\"1870\\\">Bổ sung c&aacute;c vi sinh vật c&oacute; lợi cho m&ocirc;i trường nước</p>\\n</li>\\n</ul>\\n<p data-start=\\\"1872\\\" data-end=\\\"1942\\\">Nhờ đ&oacute;, nguồn nước trở n&ecirc;n ph&ugrave; hợp hơn cho vật nu&ocirc;i sử dụng hằng ng&agrave;y.</p>\\n<h3 data-start=\\\"1944\\\" data-end=\\\"1973\\\">T&aacute;c dụng đối với vật nu&ocirc;i</h3>\\n<p data-start=\\\"1975\\\" data-end=\\\"2060\\\">Việc sử dụng nguồn nước đ&atilde; được cải thiện mang lại nhiều lợi &iacute;ch r&otilde; rệt cho vật nu&ocirc;i:</p>\\n<ul data-start=\\\"2062\\\" data-end=\\\"2368\\\">\\n<li data-start=\\\"2062\\\" data-end=\\\"2113\\\">\\n<p data-start=\\\"2064\\\" data-end=\\\"2113\\\">Tăng cường khả năng ti&ecirc;u h&oacute;a v&agrave; hấp thụ thức ăn</p>\\n</li>\\n<li data-start=\\\"2114\\\" data-end=\\\"2156\\\">\\n<p data-start=\\\"2116\\\" data-end=\\\"2156\\\">N&acirc;ng cao khả năng miễn dịch đường ruột</p>\\n</li>\\n<li data-start=\\\"2157\\\" data-end=\\\"2190\\\">\\n<p data-start=\\\"2159\\\" data-end=\\\"2190\\\">Tăng hệ số chuyển đổi thức ăn</p>\\n</li>\\n<li data-start=\\\"2191\\\" data-end=\\\"2232\\\">\\n<p data-start=\\\"2193\\\" data-end=\\\"2232\\\">Giảm v&agrave; khử m&ugrave;i h&ocirc;i trong chuồng trại</p>\\n</li>\\n<li data-start=\\\"2233\\\" data-end=\\\"2298\\\">\\n<p data-start=\\\"2235\\\" data-end=\\\"2298\\\">Cải thiện tốc độ tăng trọng, chất lượng thịt v&agrave; năng suất sữa</p>\\n</li>\\n<li data-start=\\\"2299\\\" data-end=\\\"2368\\\">\\n<p data-start=\\\"2301\\\" data-end=\\\"2368\\\">G&oacute;p phần x&acirc;y dựng m&ocirc; h&igrave;nh chăn nu&ocirc;i an to&agrave;n, hiệu quả v&agrave; bền vững</p>\\n</li>\\n</ul>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:24:56','2026-01-07 05:33:18'),
(9,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Nước Sinh Học Đa Năng BMW\"}','nuoc-sinh-hoc-da-nang-bmw','[12]',12,NULL,'[]','[]','[]','[]',0,30,1,1,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>Nước sinh học đa năng BMW l&agrave; loại nước c&oacute; thuộc t&iacute;nh sinh học t&iacute;ch cực, hỗ trợ sự ph&aacute;t triển của sinh vật. Nước chứa c&aacute;c chất hữu cơ, c&aacute;c chất chuyển h&oacute;a từ vi khuẩn v&agrave; kho&aacute;ng chất tự nhi&ecirc;n, đ&oacute;ng vai tr&ograve; quan trọng trong sản xuất n&ocirc;ng nghiệp tuần ho&agrave;n v&agrave; bảo vệ m&ocirc;i trường.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"573\\\" data-end=\\\"602\\\">Nước sinh học đa năng BMW</h3>\\n<p data-start=\\\"604\\\" data-end=\\\"920\\\">Nước sinh học đa năng BMW l&agrave; loại nước c&oacute; thuộc t&iacute;nh tốt cho sự ph&aacute;t triển của sinh vật, được tạo ra từ qu&aacute; tr&igrave;nh hoạt động sinh học tự nhi&ecirc;n của vi khuẩn kết hợp với c&aacute;c kho&aacute;ng chất tự nhi&ecirc;n. Th&agrave;nh phần của nước bao gồm c&aacute;c chất hữu cơ, c&aacute;c chất chuyển h&oacute;a từ vi khuẩn v&agrave; c&aacute;c kho&aacute;ng chất cần thiết cho hệ sinh th&aacute;i.</p>\\n<p data-start=\\\"922\\\" data-end=\\\"1087\\\">Nhờ đặc t&iacute;nh sinh học ổn định, nước sinh học BMW c&oacute; thể được sử dụng linh hoạt trong nhiều lĩnh vực, đặc biệt l&agrave; trong n&ocirc;ng nghiệp v&agrave; c&aacute;c m&ocirc; h&igrave;nh sản xuất tuần ho&agrave;n.</p>\\n<h3 data-start=\\\"1089\\\" data-end=\\\"1123\\\">T&aacute;c dụng của nước sinh học BMW</h3>\\n<p data-start=\\\"1125\\\" data-end=\\\"1227\\\">Nước sinh học đa năng BMW mang lại nhiều t&aacute;c dụng quan trọng đối với m&ocirc;i trường v&agrave; qu&aacute; tr&igrave;nh sản xuất:</p>\\n<ul data-start=\\\"1229\\\" data-end=\\\"1488\\\">\\n<li data-start=\\\"1229\\\" data-end=\\\"1292\\\">\\n<p data-start=\\\"1231\\\" data-end=\\\"1292\\\">K&iacute;ch hoạt v&agrave; th&uacute;c đẩy sự ph&aacute;t triển của c&aacute;c vi khuẩn c&oacute; lợi</p>\\n</li>\\n<li data-start=\\\"1293\\\" data-end=\\\"1350\\\">\\n<p data-start=\\\"1295\\\" data-end=\\\"1350\\\">Ức chế qu&aacute; tr&igrave;nh thối rữa v&agrave; ph&acirc;n hủy kh&ocirc;ng kiểm so&aacute;t</p>\\n</li>\\n<li data-start=\\\"1351\\\" data-end=\\\"1416\\\">\\n<p data-start=\\\"1353\\\" data-end=\\\"1416\\\">Th&uacute;c đẩy qu&aacute; tr&igrave;nh ph&acirc;n giải c&aacute;c chất hữu cơ trong m&ocirc;i trường</p>\\n</li>\\n<li data-start=\\\"1417\\\" data-end=\\\"1488\\\">\\n<p data-start=\\\"1419\\\" data-end=\\\"1488\\\">G&oacute;p phần x&acirc;y dựng v&agrave; duy tr&igrave; m&ocirc; h&igrave;nh sản xuất n&ocirc;ng nghiệp tuần ho&agrave;n</p>\\n</li>\\n</ul>\\n<p data-start=\\\"1490\\\" data-end=\\\"1665\\\">Th&ocirc;ng qua c&aacute;c t&aacute;c dụng n&agrave;y, nước sinh học BMW đ&oacute;ng vai tr&ograve; l&agrave; một sản phẩm nền tảng trong việc t&aacute;i tạo t&agrave;i nguy&ecirc;n, n&acirc;ng cao hiệu quả sản xuất v&agrave; hướng tới ph&aacute;t triển bền vững.</p>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:27:40','2026-01-09 04:07:23'),
(10,'{\"en\": \"En\", \"ja\": \"JP\", \"vi\": \"Ứng Dụng Trong Nông Nghiệp - Trồng Trọt\"}','ung-dung-trong-nong-nghiep-trong-trot','[13]',18,NULL,'[]','[]','[]','[]',0,5,1,1,NULL,'{\"en\": \"<p>En</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>Nước sinh học đa năng BMW gi&uacute;p k&iacute;ch th&iacute;ch sinh trưởng c&acirc;y trồng, n&acirc;ng cao khả năng hấp thu dinh dưỡng v&agrave; tăng sức đề kh&aacute;ng tự nhi&ecirc;n. Sản phẩm hỗ trợ n&acirc;ng cao năng suất, chất lượng n&ocirc;ng sản v&agrave; ph&ugrave; hợp cho c&aacute;c m&ocirc; h&igrave;nh sản xuất n&ocirc;ng nghiệp tuần ho&agrave;n.</p>\"}','{\"en\": \"<p>En</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"552\\\" data-end=\\\"603\\\">T&aacute;c dụng của nước sinh học BMW trong trồng trọt</h3>\\n<p data-start=\\\"605\\\" data-end=\\\"716\\\">Nước sinh học đa năng BMW mang lại nhiều lợi &iacute;ch thiết thực cho c&acirc;y trồng trong qu&aacute; tr&igrave;nh canh t&aacute;c n&ocirc;ng nghiệp:</p>\\n<ul data-start=\\\"718\\\" data-end=\\\"985\\\">\\n<li data-start=\\\"718\\\" data-end=\\\"818\\\">\\n<p data-start=\\\"720\\\" data-end=\\\"818\\\">K&iacute;ch th&iacute;ch qu&aacute; tr&igrave;nh nảy mầm, ph&aacute;t triển bộ rễ v&agrave; tăng khả năng hấp thu dinh dưỡng của c&acirc;y trồng</p>\\n</li>\\n<li data-start=\\\"819\\\" data-end=\\\"870\\\">\\n<p data-start=\\\"821\\\" data-end=\\\"870\\\">Th&uacute;c đẩy sinh trưởng, ra hoa v&agrave; đậu quả ổn định</p>\\n</li>\\n<li data-start=\\\"871\\\" data-end=\\\"916\\\">\\n<p data-start=\\\"873\\\" data-end=\\\"916\\\">N&acirc;ng cao năng suất v&agrave; chất lượng n&ocirc;ng sản</p>\\n</li>\\n<li data-start=\\\"917\\\" data-end=\\\"985\\\">\\n<p data-start=\\\"919\\\" data-end=\\\"985\\\">Tăng sức đề kh&aacute;ng tự nhi&ecirc;n của c&acirc;y trồng, g&oacute;p phần giảm s&acirc;u bệnh</p>\\n</li>\\n</ul>\\n<p data-start=\\\"987\\\" data-end=\\\"1102\\\">Nhờ c&aacute;c t&aacute;c dụng n&agrave;y, nước sinh học BMW ph&ugrave; hợp cho nhiều loại c&acirc;y trồng v&agrave; m&ocirc; h&igrave;nh sản xuất n&ocirc;ng nghiệp kh&aacute;c nhau.</p>\\n<h3 data-start=\\\"1104\\\" data-end=\\\"1138\\\">C&aacute;ch sử dụng nước sinh học BMW</h3>\\n<p data-start=\\\"1140\\\" data-end=\\\"1220\\\">Để đạt hiệu quả tối ưu, nước sinh học BMW được sử dụng theo c&aacute;c phương ph&aacute;p sau:</p>\\n<ul data-start=\\\"1222\\\" data-end=\\\"1446\\\">\\n<li data-start=\\\"1222\\\" data-end=\\\"1336\\\">\\n<p data-start=\\\"1224\\\" data-end=\\\"1336\\\"><strong data-start=\\\"1224\\\" data-end=\\\"1271\\\">Ng&acirc;m hạt giống hoặc rễ c&acirc;y trước khi trồng:</strong> pha lo&atilde;ng nước sinh học BMW với nước sạch theo tỷ lệ <strong data-start=\\\"1325\\\" data-end=\\\"1334\\\">1:100</strong></p>\\n</li>\\n<li data-start=\\\"1337\\\" data-end=\\\"1446\\\">\\n<p data-start=\\\"1339\\\" data-end=\\\"1446\\\"><strong data-start=\\\"1339\\\" data-end=\\\"1381\\\">Tưới gốc hoặc phun b&oacute;n qua l&aacute; định kỳ:</strong> pha lo&atilde;ng nước sinh học BMW với nước sạch theo tỷ lệ <strong data-start=\\\"1435\\\" data-end=\\\"1444\\\">1:100</strong></p>\\n</li>\\n</ul>\\n<p data-start=\\\"1448\\\" data-end=\\\"1545\\\">Việc sử dụng đ&uacute;ng liều lượng v&agrave; định kỳ gi&uacute;p c&acirc;y trồng ph&aacute;t triển khỏe mạnh, ổn định v&agrave; bền vững.</p>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:29:34','2026-01-09 04:07:33'),
(11,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Ứng Dụng Trong Chăn Nuôi\"}','ung-dung-trong-chan-nuoi','[13]',19,NULL,'[]','[]','[]','[]',0,3,1,1,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>Nước sinh học đa năng BMW hỗ trợ cải thiện ti&ecirc;u h&oacute;a, tăng cường miễn dịch đường ruột v&agrave; n&acirc;ng cao hiệu quả chăn nu&ocirc;i. Sản phẩm gi&uacute;p giảm m&ugrave;i h&ocirc;i chuồng trại, cải thiện chất lượng thịt, năng suất sữa v&agrave; tỷ lệ sinh sản, ph&ugrave; hợp cho c&aacute;c m&ocirc; h&igrave;nh chăn nu&ocirc;i an to&agrave;n v&agrave; bền vững.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"575\\\" data-end=\\\"625\\\">T&aacute;c dụng của nước sinh học BMW trong chăn nu&ocirc;i</h3>\\n<p data-start=\\\"627\\\" data-end=\\\"713\\\">Nước sinh học đa năng BMW mang lại nhiều lợi &iacute;ch thiết thực trong hoạt động chăn nu&ocirc;i:</p>\\n<ul data-start=\\\"715\\\" data-end=\\\"1091\\\">\\n<li data-start=\\\"715\\\" data-end=\\\"791\\\">\\n<p data-start=\\\"717\\\" data-end=\\\"791\\\">Tăng cường ti&ecirc;u h&oacute;a, khả năng hấp thu dinh dưỡng v&agrave; miễn dịch đường ruột</p>\\n</li>\\n<li data-start=\\\"792\\\" data-end=\\\"849\\\">\\n<p data-start=\\\"794\\\" data-end=\\\"849\\\">G&oacute;p phần ngăn ngừa c&aacute;c bệnh li&ecirc;n quan đến hệ ti&ecirc;u h&oacute;a</p>\\n</li>\\n<li data-start=\\\"850\\\" data-end=\\\"916\\\">\\n<p data-start=\\\"852\\\" data-end=\\\"916\\\">Cải thiện tốc độ tăng trưởng v&agrave; hệ số chuyển đổi thức ăn (FCR)</p>\\n</li>\\n<li data-start=\\\"917\\\" data-end=\\\"978\\\">\\n<p data-start=\\\"919\\\" data-end=\\\"978\\\">N&acirc;ng cao chất lượng thịt, năng suất sữa v&agrave; tỷ lệ sinh sản</p>\\n</li>\\n<li data-start=\\\"979\\\" data-end=\\\"1031\\\">\\n<p data-start=\\\"981\\\" data-end=\\\"1031\\\">Giảm t&igrave;nh trạng vỡ trứng trong chăn nu&ocirc;i gia cầm</p>\\n</li>\\n<li data-start=\\\"1032\\\" data-end=\\\"1091\\\">\\n<p data-start=\\\"1034\\\" data-end=\\\"1091\\\">Khử m&ugrave;i h&ocirc;i chuồng trại, cải thiện m&ocirc;i trường chăn nu&ocirc;i</p>\\n</li>\\n</ul>\\n<p data-start=\\\"1093\\\" data-end=\\\"1206\\\">Nhờ c&aacute;c t&aacute;c dụng n&agrave;y, nước sinh học BMW gi&uacute;p n&acirc;ng cao hiệu quả sản xuất v&agrave; giảm rủi ro trong qu&aacute; tr&igrave;nh chăn nu&ocirc;i.</p>\\n<h3 data-start=\\\"1208\\\" data-end=\\\"1258\\\">C&aacute;ch sử dụng nước sinh học BMW trong chăn nu&ocirc;i</h3>\\n<p data-start=\\\"1260\\\" data-end=\\\"1339\\\">Nước sinh học BMW c&oacute; thể được sử dụng linh hoạt theo nhiều h&igrave;nh thức kh&aacute;c nhau:</p>\\n<ul data-start=\\\"1341\\\" data-end=\\\"1498\\\">\\n<li data-start=\\\"1341\\\" data-end=\\\"1375\\\">\\n<p data-start=\\\"1343\\\" data-end=\\\"1375\\\">Pha v&agrave;o nước uống cho vật nu&ocirc;i</p>\\n</li>\\n<li data-start=\\\"1376\\\" data-end=\\\"1400\\\">\\n<p data-start=\\\"1378\\\" data-end=\\\"1400\\\">Sử dụng để ủ thức ăn</p>\\n</li>\\n<li data-start=\\\"1401\\\" data-end=\\\"1436\\\">\\n<p data-start=\\\"1403\\\" data-end=\\\"1436\\\">Xử l&yacute; chất đệm l&oacute;t cho vật nu&ocirc;i</p>\\n</li>\\n<li data-start=\\\"1437\\\" data-end=\\\"1456\\\">\\n<p data-start=\\\"1439\\\" data-end=\\\"1456\\\">Rửa chuồng trại</p>\\n</li>\\n<li data-start=\\\"1457\\\" data-end=\\\"1498\\\">\\n<p data-start=\\\"1459\\\" data-end=\\\"1498\\\">Xử l&yacute; m&ugrave;i h&ocirc;i trong khu vực chăn nu&ocirc;i</p>\\n</li>\\n</ul>\\n<p data-start=\\\"1500\\\" data-end=\\\"1622\\\"><strong data-start=\\\"1500\\\" data-end=\\\"1523\\\">Liều lượng sử dụng:</strong><br data-start=\\\"1523\\\" data-end=\\\"1526\\\">Sử dụng nước sinh học BMW pha lo&atilde;ng với nước sạch theo tỷ lệ <strong data-start=\\\"1587\\\" data-end=\\\"1596\\\">1:100</strong> để đạt hiệu quả tốt nhất.</p>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:31:21','2026-01-07 06:23:26'),
(12,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Ứng Dụng Trong Thủy Hải Sản\"}','ung-dung-trong-thuy-hai-san','[13]',20,NULL,'[]','[]','[]','[]',0,2,0,0,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>Nước sinh học đa năng BMW gi&uacute;p cải thiện m&ocirc;i trường nước ao nu&ocirc;i th&ocirc;ng qua th&uacute;c đẩy ph&acirc;n hủy chất hữu cơ, ổn định chất lượng nước v&agrave; ức chế vi khuẩn g&acirc;y bệnh. Sản phẩm g&oacute;p phần n&acirc;ng cao hiệu quả nu&ocirc;i trồng thủy sản, giảm chi ph&iacute; xử l&yacute; m&ocirc;i trường v&agrave; hạn chế sử dụng kh&aacute;ng sinh.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"609\\\" data-end=\\\"669\\\">T&aacute;c dụng của nước sinh học BMW trong nu&ocirc;i trồng thủy sản</h3>\\n<p data-start=\\\"671\\\" data-end=\\\"787\\\">Nước sinh học đa năng BMW mang lại nhiều lợi &iacute;ch quan trọng cho m&ocirc;i trường ao nu&ocirc;i v&agrave; qu&aacute; tr&igrave;nh nu&ocirc;i trồng thủy sản:</p>\\n<ul data-start=\\\"789\\\" data-end=\\\"1217\\\">\\n<li data-start=\\\"789\\\" data-end=\\\"858\\\">\\n<p data-start=\\\"791\\\" data-end=\\\"858\\\">Th&uacute;c đẩy qu&aacute; tr&igrave;nh ph&acirc;n hủy c&aacute;c chất hữu cơ t&iacute;ch tụ trong ao nu&ocirc;i</p>\\n</li>\\n<li data-start=\\\"859\\\" data-end=\\\"933\\\">\\n<p data-start=\\\"861\\\" data-end=\\\"933\\\">Ổn định chất lượng nước, g&oacute;p phần giảm c&aacute;c kh&iacute; độc như NH₃, NO₂ v&agrave; H₂S</p>\\n</li>\\n<li data-start=\\\"934\\\" data-end=\\\"1002\\\">\\n<p data-start=\\\"936\\\" data-end=\\\"1002\\\">Ức chế sự ph&aacute;t triển của vi khuẩn g&acirc;y bệnh trong m&ocirc;i trường nước</p>\\n</li>\\n<li data-start=\\\"1003\\\" data-end=\\\"1076\\\">\\n<p data-start=\\\"1005\\\" data-end=\\\"1076\\\">Tăng cường sức đề kh&aacute;ng, miễn dịch tự nhi&ecirc;n v&agrave; n&acirc;ng cao hiệu quả nu&ocirc;i</p>\\n</li>\\n<li data-start=\\\"1077\\\" data-end=\\\"1145\\\">\\n<p data-start=\\\"1079\\\" data-end=\\\"1145\\\">Giảm chi ph&iacute; xử l&yacute; m&ocirc;i trường v&agrave; hạn chế việc sử dụng kh&aacute;ng sinh</p>\\n</li>\\n<li data-start=\\\"1146\\\" data-end=\\\"1217\\\">\\n<p data-start=\\\"1148\\\" data-end=\\\"1217\\\">Bổ sung c&aacute;c kho&aacute;ng chất tự nhi&ecirc;n cần thiết cho hệ sinh th&aacute;i ao nu&ocirc;i</p>\\n</li>\\n</ul>\\n<p data-start=\\\"1219\\\" data-end=\\\"1330\\\">Nhờ c&aacute;c t&aacute;c dụng n&agrave;y, nước sinh học BMW gi&uacute;p duy tr&igrave; m&ocirc;i trường nước ổn định, an to&agrave;n v&agrave; bền vững cho thủy sản.</p>\\n<h3 data-start=\\\"1332\\\" data-end=\\\"1380\\\">C&aacute;ch sử dụng nước sinh học BMW trong ao nu&ocirc;i</h3>\\n<p data-start=\\\"1382\\\" data-end=\\\"1456\\\">Để đạt hiệu quả tối ưu, nước sinh học BMW được sử dụng theo hướng dẫn sau:</p>\\n<ul data-start=\\\"1458\\\" data-end=\\\"1614\\\">\\n<li data-start=\\\"1458\\\" data-end=\\\"1536\\\">\\n<p data-start=\\\"1460\\\" data-end=\\\"1536\\\">Tạt đều nước sinh học BMW tr&ecirc;n khắp bề mặt ao theo định kỳ <strong data-start=\\\"1519\\\" data-end=\\\"1534\\\">7 &ndash; 10 ng&agrave;y</strong></p>\\n</li>\\n<li data-start=\\\"1537\\\" data-end=\\\"1614\\\">\\n<p data-start=\\\"1539\\\" data-end=\\\"1614\\\">Liều lượng sử dụng: <strong data-start=\\\"1559\\\" data-end=\\\"1612\\\">1 l&iacute;t nước sinh học BMW cho 500 &ndash; 1000 m&sup3; nước ao</strong></p>\\n</li>\\n</ul>\\n<p data-start=\\\"1616\\\" data-end=\\\"1740\\\">Việc sử dụng đ&uacute;ng liều lượng v&agrave; định kỳ gi&uacute;p cải thiện chất lượng nước ao, hỗ trợ thủy sản sinh trưởng khỏe mạnh v&agrave; ổn định.</p>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:32:28','2026-01-09 04:07:38'),
(13,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Ứng Dụng Trong Xử Lý Môi Trường\"}','ung-dung-trong-xu-ly-moi-truong','[13]',21,NULL,'[]','[]','[]','[]',0,7,0,0,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>Nước sinh học đa năng BMW được ứng dụng hiệu quả trong xử l&yacute; bể phốt, ủ ph&acirc;n v&agrave; r&aacute;c thải hữu cơ, xử l&yacute; chất đệm l&oacute;t vật nu&ocirc;i v&agrave; cống r&atilde;nh. Sản phẩm gi&uacute;p th&uacute;c đẩy ph&acirc;n hủy chất hữu cơ, giảm m&ugrave;i h&ocirc;i v&agrave; g&oacute;p phần bảo vệ m&ocirc;i trường sống bền vững.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"521\\\" data-end=\\\"574\\\">Ứng dụng nước sinh học BMW trong xử l&yacute; m&ocirc;i trường</h3>\\n<p data-start=\\\"576\\\" data-end=\\\"737\\\">Nước sinh học đa năng BMW mang lại hiệu quả cao trong việc xử l&yacute; chất thải sinh hoạt, chăn nu&ocirc;i v&agrave; m&ocirc;i trường, g&oacute;p phần giảm &ocirc; nhiễm v&agrave; cải thiện điều kiện sống.</p>\\n<h3 data-start=\\\"739\\\" data-end=\\\"756\\\">Xử l&yacute; bể phốt</h3>\\n<p data-start=\\\"758\\\" data-end=\\\"892\\\">Nước sinh học BMW được sử dụng để hỗ trợ ph&acirc;n hủy chất hữu cơ trong bể phốt, giảm m&ugrave;i h&ocirc;i v&agrave; duy tr&igrave; hoạt động ổn định của hệ vi sinh:</p>\\n<ul data-start=\\\"894\\\" data-end=\\\"989\\\">\\n<li data-start=\\\"894\\\" data-end=\\\"945\\\">\\n<p data-start=\\\"896\\\" data-end=\\\"945\\\">Liều lượng sử dụng: <strong data-start=\\\"916\\\" data-end=\\\"943\\\">500 ml cho 1 m&sup3; bể phốt</strong></p>\\n</li>\\n<li data-start=\\\"946\\\" data-end=\\\"989\\\">\\n<p data-start=\\\"948\\\" data-end=\\\"989\\\">Tần suất sử dụng: <strong data-start=\\\"966\\\" data-end=\\\"989\\\">định kỳ 15 ng&agrave;y/lần</strong></p>\\n</li>\\n</ul>\\n<h3 data-start=\\\"991\\\" data-end=\\\"1020\\\">Ủ ph&acirc;n v&agrave; r&aacute;c thải hữu cơ</h3>\\n<p data-start=\\\"1022\\\" data-end=\\\"1150\\\">Nước sinh học BMW hỗ trợ qu&aacute; tr&igrave;nh ủ ph&acirc;n v&agrave; r&aacute;c thải hữu cơ diễn ra nhanh hơn, giảm m&ugrave;i v&agrave; tạo ra nguồn ph&acirc;n hữu cơ chất lượng:</p>\\n<ul data-start=\\\"1152\\\" data-end=\\\"1238\\\">\\n<li data-start=\\\"1152\\\" data-end=\\\"1179\\\">\\n<p data-start=\\\"1154\\\" data-end=\\\"1179\\\">Ủ ph&acirc;n gia s&uacute;c, gia cầm</p>\\n</li>\\n<li data-start=\\\"1180\\\" data-end=\\\"1211\\\">\\n<p data-start=\\\"1182\\\" data-end=\\\"1211\\\">Ủ r&aacute;c thải sinh hoạt hữu cơ</p>\\n</li>\\n<li data-start=\\\"1212\\\" data-end=\\\"1238\\\">\\n<p data-start=\\\"1214\\\" data-end=\\\"1238\\\">Ủ phụ phẩm n&ocirc;ng nghiệp</p>\\n</li>\\n</ul>\\n<p data-start=\\\"1240\\\" data-end=\\\"1372\\\"><strong data-start=\\\"1240\\\" data-end=\\\"1257\\\">C&aacute;ch sử dụng:</strong><br data-start=\\\"1257\\\" data-end=\\\"1260\\\">Pha lo&atilde;ng nước sinh học BMW với nước sạch theo tỷ lệ <strong data-start=\\\"1313\\\" data-end=\\\"1322\\\">1:100</strong>, sau đ&oacute; phun hoặc tưới đều l&ecirc;n nguy&ecirc;n liệu cần ủ.</p>\\n<h3 data-start=\\\"1374\\\" data-end=\\\"1405\\\">Xử l&yacute; chất đệm l&oacute;t vật nu&ocirc;i</h3>\\n<p data-start=\\\"1407\\\" data-end=\\\"1523\\\">Nước sinh học BMW gi&uacute;p giảm m&ugrave;i h&ocirc;i, th&uacute;c đẩy ph&acirc;n hủy chất thải trong chất đệm l&oacute;t, cải thiện m&ocirc;i trường chăn nu&ocirc;i:</p>\\n<ul data-start=\\\"1525\\\" data-end=\\\"1594\\\">\\n<li data-start=\\\"1525\\\" data-end=\\\"1559\\\">\\n<p data-start=\\\"1527\\\" data-end=\\\"1559\\\">Pha lo&atilde;ng theo tỷ lệ <strong data-start=\\\"1548\\\" data-end=\\\"1557\\\">1:100</strong></p>\\n</li>\\n<li data-start=\\\"1560\\\" data-end=\\\"1594\\\">\\n<p data-start=\\\"1562\\\" data-end=\\\"1594\\\">Phun đều l&ecirc;n bề mặt chất đệm l&oacute;t</p>\\n</li>\\n</ul>\\n<h3 data-start=\\\"1596\\\" data-end=\\\"1615\\\">Xử l&yacute; cống r&atilde;nh</h3>\\n<p data-start=\\\"1617\\\" data-end=\\\"1732\\\">Trong xử l&yacute; cống r&atilde;nh v&agrave; khu vực ph&aacute;t sinh m&ugrave;i h&ocirc;i, nước sinh học BMW được sử dụng trực tiếp để đạt hiệu quả nhanh:</p>\\n<ul data-start=\\\"1734\\\" data-end=\\\"1771\\\">\\n<li data-start=\\\"1734\\\" data-end=\\\"1771\\\">\\n<p data-start=\\\"1736\\\" data-end=\\\"1771\\\"><strong data-start=\\\"1736\\\" data-end=\\\"1771\\\">Phun trực tiếp, kh&ocirc;ng pha lo&atilde;ng</strong></p>\\n</li>\\n</ul>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:34:04','2026-01-09 04:07:36'),
(14,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Ứng Dụng Trong Đời Sống Hàng Ngày\"}','ung-dung-trong-doi-song-hang-ngay','[13]',22,NULL,'[]','[]','[]','[]',0,24,1,1,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>Nước sinh học đa năng BMW được ứng dụng linh hoạt trong đời sống hằng ng&agrave;y như chăm s&oacute;c th&uacute; cưng, bể c&aacute;, cắm hoa, chăm s&oacute;c c&acirc;y cảnh, vệ sinh nh&agrave; bếp &ndash; ph&ograve;ng tắm v&agrave; giặt l&agrave;. Sản phẩm gi&uacute;p khử khuẩn, khử m&ugrave;i, bổ sung kho&aacute;ng chất v&agrave; cải thiện m&ocirc;i trường sống an to&agrave;n, th&acirc;n thiện.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"539\\\" data-end=\\\"584\\\">Ứng dụng nước sinh học BMW trong đời sống</h3>\\n<p data-start=\\\"586\\\" data-end=\\\"780\\\">Nước sinh học đa năng BMW kh&ocirc;ng chỉ được sử dụng trong n&ocirc;ng nghiệp v&agrave; m&ocirc;i trường m&agrave; c&ograve;n mang lại nhiều lợi &iacute;ch thiết thực trong sinh hoạt hằng ng&agrave;y, g&oacute;p phần n&acirc;ng cao chất lượng m&ocirc;i trường sống.</p>\\n<h3 data-start=\\\"782\\\" data-end=\\\"802\\\">Đối với th&uacute; cưng</h3>\\n<p data-start=\\\"804\\\" data-end=\\\"877\\\">Nước sinh học BMW gi&uacute;p khử m&ugrave;i v&agrave; cải thiện m&ocirc;i trường sống cho th&uacute; cưng:</p>\\n<ul data-start=\\\"879\\\" data-end=\\\"988\\\">\\n<li data-start=\\\"879\\\" data-end=\\\"936\\\">\\n<p data-start=\\\"881\\\" data-end=\\\"936\\\">Khử m&ugrave;i chuồng trại v&agrave; khu vực sinh hoạt của th&uacute; cưng</p>\\n</li>\\n<li data-start=\\\"937\\\" data-end=\\\"988\\\">\\n<p data-start=\\\"939\\\" data-end=\\\"988\\\">C&aacute;ch sử dụng: <strong data-start=\\\"953\\\" data-end=\\\"988\\\">phun trực tiếp, kh&ocirc;ng pha lo&atilde;ng</strong></p>\\n</li>\\n</ul>\\n<h3 data-start=\\\"990\\\" data-end=\\\"1007\\\">Đối với bể c&aacute;</h3>\\n<p data-start=\\\"1009\\\" data-end=\\\"1086\\\">Nước sinh học BMW hỗ trợ duy tr&igrave; m&ocirc;i trường nước sạch v&agrave; ổn định cho c&aacute; cảnh:</p>\\n<ul data-start=\\\"1088\\\" data-end=\\\"1242\\\">\\n<li data-start=\\\"1088\\\" data-end=\\\"1116\\\">\\n<p data-start=\\\"1090\\\" data-end=\\\"1116\\\">Khử khuẩn, l&agrave;m sạch nước</p>\\n</li>\\n<li data-start=\\\"1117\\\" data-end=\\\"1170\\\">\\n<p data-start=\\\"1119\\\" data-end=\\\"1170\\\">Bổ sung kho&aacute;ng chất tự nhi&ecirc;n cho m&ocirc;i trường bể c&aacute;</p>\\n</li>\\n<li data-start=\\\"1171\\\" data-end=\\\"1242\\\">\\n<p data-start=\\\"1173\\\" data-end=\\\"1242\\\">Liều lượng sử dụng: <strong data-start=\\\"1193\\\" data-end=\\\"1218\\\">1 l&iacute;t cho 500 m&sup3; nước</strong>, định kỳ <strong data-start=\\\"1228\\\" data-end=\\\"1242\\\">7 ng&agrave;y/lần</strong></p>\\n</li>\\n</ul>\\n<h3 data-start=\\\"1244\\\" data-end=\\\"1270\\\">Ứng dụng trong cắm hoa</h3>\\n<p data-start=\\\"1272\\\" data-end=\\\"1323\\\">Nước sinh học BMW gi&uacute;p k&eacute;o d&agrave;i độ tươi của hoa cắm:</p>\\n<ul data-start=\\\"1325\\\" data-end=\\\"1420\\\">\\n<li data-start=\\\"1325\\\" data-end=\\\"1376\\\">\\n<p data-start=\\\"1327\\\" data-end=\\\"1376\\\">Nhỏ <strong data-start=\\\"1331\\\" data-end=\\\"1345\\\">3 &ndash; 5 giọt</strong> nước sinh học BMW v&agrave;o lọ hoa</p>\\n</li>\\n<li data-start=\\\"1377\\\" data-end=\\\"1420\\\">\\n<p data-start=\\\"1379\\\" data-end=\\\"1420\\\">Gi&uacute;p hoa tươi l&acirc;u v&agrave; hạn chế m&ugrave;i kh&oacute; chịu</p>\\n</li>\\n</ul>\\n<h3 data-start=\\\"1422\\\" data-end=\\\"1443\\\">Chăm s&oacute;c c&acirc;y cảnh</h3>\\n<p data-start=\\\"1445\\\" data-end=\\\"1500\\\">Nước sinh học BMW hỗ trợ c&acirc;y cảnh ph&aacute;t triển khỏe mạnh:</p>\\n<ul data-start=\\\"1502\\\" data-end=\\\"1586\\\">\\n<li data-start=\\\"1502\\\" data-end=\\\"1536\\\">\\n<p data-start=\\\"1504\\\" data-end=\\\"1536\\\">Pha lo&atilde;ng theo tỷ lệ <strong data-start=\\\"1525\\\" data-end=\\\"1534\\\">1:100</strong></p>\\n</li>\\n<li data-start=\\\"1537\\\" data-end=\\\"1586\\\">\\n<p data-start=\\\"1539\\\" data-end=\\\"1586\\\">Tưới gốc v&agrave; phun l&aacute; định kỳ <strong data-start=\\\"1567\\\" data-end=\\\"1586\\\">7 &ndash; 10 ng&agrave;y/lần</strong></p>\\n</li>\\n</ul>\\n<h3 data-start=\\\"1588\\\" data-end=\\\"1612\\\">Nh&agrave; bếp v&agrave; ph&ograve;ng tắm</h3>\\n<p data-start=\\\"1614\\\" data-end=\\\"1694\\\">Nước sinh học BMW được sử dụng để vệ sinh v&agrave; khử m&ugrave;i trong kh&ocirc;ng gian sinh hoạt:</p>\\n<ul data-start=\\\"1696\\\" data-end=\\\"1803\\\">\\n<li data-start=\\\"1696\\\" data-end=\\\"1751\\\">\\n<p data-start=\\\"1698\\\" data-end=\\\"1751\\\">Khử khuẩn, khử m&ugrave;i tại khu vực nh&agrave; bếp v&agrave; ph&ograve;ng tắm</p>\\n</li>\\n<li data-start=\\\"1752\\\" data-end=\\\"1803\\\">\\n<p data-start=\\\"1754\\\" data-end=\\\"1803\\\">C&aacute;ch sử dụng: <strong data-start=\\\"1768\\\" data-end=\\\"1803\\\">phun trực tiếp, kh&ocirc;ng pha lo&atilde;ng</strong></p>\\n</li>\\n</ul>\\n<h3 data-start=\\\"1805\\\" data-end=\\\"1831\\\">Ứng dụng trong giặt l&agrave;</h3>\\n<p data-start=\\\"1833\\\" data-end=\\\"1895\\\">Nước sinh học BMW gi&uacute;p giảm m&ugrave;i h&oacute;a chất trong qu&aacute; tr&igrave;nh giặt:</p>\\n<ul data-start=\\\"1897\\\" data-end=\\\"1994\\\">\\n<li data-start=\\\"1897\\\" data-end=\\\"1932\\\">\\n<p data-start=\\\"1899\\\" data-end=\\\"1932\\\">Khử m&ugrave;i bột giặt v&agrave; m&ugrave;i quần &aacute;o</p>\\n</li>\\n<li data-start=\\\"1933\\\" data-end=\\\"1994\\\">\\n<p data-start=\\\"1935\\\" data-end=\\\"1994\\\">C&aacute;ch sử dụng: <strong data-start=\\\"1949\\\" data-end=\\\"1994\\\">th&ecirc;m 1 cốc nước sinh học BMW v&agrave;o m&aacute;y giặt</strong></p>\\n</li>\\n</ul>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 03:35:18','2026-01-09 03:40:00'),
(15,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Ứng dụng công nghệ và nước sinh học đa năng BMW\"}','ung-dung-cong-nghe-va-nuoc-sinh-hoc-da-nang-bmw','[]',13,NULL,'[]','[]','[]','[]',0,67,1,1,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>C&ocirc;ng nghệ v&agrave; nước sinh học đa năng BMW được ứng dụng rộng r&atilde;i trong n&ocirc;ng nghiệp, chăn nu&ocirc;i, thủy sản, xử l&yacute; m&ocirc;i trường v&agrave; đời sống hằng ng&agrave;y. C&aacute;c ứng dụng n&agrave;y gi&uacute;p tối ưu t&agrave;i nguy&ecirc;n, giảm &ocirc; nhiễm v&agrave; hướng tới m&ocirc; h&igrave;nh sản xuất &ndash; sinh hoạt bền vững.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"496\\\" data-end=\\\"547\\\">Ứng dụng c&ocirc;ng nghệ v&agrave; nước sinh học đa năng BMW</h3>\\n<p data-start=\\\"549\\\" data-end=\\\"858\\\">C&ocirc;ng nghệ BMW (Bacteria &ndash; Mineral &ndash; Water) v&agrave; nước sinh học đa năng BMW được ph&aacute;t triển dựa tr&ecirc;n nguy&ecirc;n l&yacute; tuần ho&agrave;n tự nhi&ecirc;n, tận dụng vi sinh vật v&agrave; kho&aacute;ng chất để cải thiện m&ocirc;i trường đất, nước v&agrave; kh&ocirc;ng kh&iacute;. Nhờ t&iacute;nh linh hoạt v&agrave; an to&agrave;n sinh học, BMW được ứng dụng rộng r&atilde;i trong nhiều lĩnh vực kh&aacute;c nhau.</p>\\n<h3 data-start=\\\"860\\\" data-end=\\\"890\\\">Ứng dụng trong n&ocirc;ng nghiệp</h3>\\n<p data-start=\\\"892\\\" data-end=\\\"1239\\\">Trong trồng trọt, nước sinh học BMW gi&uacute;p k&iacute;ch th&iacute;ch nảy mầm, ph&aacute;t triển bộ rễ, tăng khả năng hấp thu dinh dưỡng v&agrave; th&uacute;c đẩy sinh trưởng của c&acirc;y trồng. Việc sử dụng BMW g&oacute;p phần n&acirc;ng cao năng suất, cải thiện chất lượng n&ocirc;ng sản, đồng thời tăng sức đề kh&aacute;ng tự nhi&ecirc;n v&agrave; giảm s&acirc;u bệnh, ph&ugrave; hợp với m&ocirc; h&igrave;nh n&ocirc;ng nghiệp hữu cơ v&agrave; n&ocirc;ng nghiệp tuần ho&agrave;n.</p>\\n<h3 data-start=\\\"1241\\\" data-end=\\\"1269\\\">Ứng dụng trong chăn nu&ocirc;i</h3>\\n<p data-start=\\\"1271\\\" data-end=\\\"1590\\\">Trong chăn nu&ocirc;i, BMW được sử dụng để cải thiện ti&ecirc;u h&oacute;a, tăng cường miễn dịch đường ruột v&agrave; n&acirc;ng cao hiệu quả sử dụng thức ăn. Nước sinh học BMW c&ograve;n gi&uacute;p giảm m&ugrave;i h&ocirc;i chuồng trại, cải thiện m&ocirc;i trường chăn nu&ocirc;i, n&acirc;ng cao chất lượng thịt, năng suất sữa v&agrave; tỷ lệ sinh sản, hướng tới m&ocirc; h&igrave;nh chăn nu&ocirc;i an to&agrave;n v&agrave; bền vững.</p>\\n<h3 data-start=\\\"1592\\\" data-end=\\\"1630\\\">Ứng dụng trong nu&ocirc;i trồng thủy sản</h3>\\n<p data-start=\\\"1632\\\" data-end=\\\"1916\\\">Trong nu&ocirc;i trồng thủy sản, BMW gi&uacute;p th&uacute;c đẩy ph&acirc;n hủy chất hữu cơ, ổn định chất lượng nước v&agrave; giảm c&aacute;c kh&iacute; độc trong ao nu&ocirc;i. Việc sử dụng nước sinh học BMW g&oacute;p phần ức chế vi khuẩn g&acirc;y bệnh, tăng sức đề kh&aacute;ng cho thủy sản, giảm chi ph&iacute; xử l&yacute; m&ocirc;i trường v&agrave; hạn chế sử dụng kh&aacute;ng sinh.</p>\\n<h3 data-start=\\\"1918\\\" data-end=\\\"1953\\\">Ứng dụng trong xử l&yacute; m&ocirc;i trường</h3>\\n<p data-start=\\\"1955\\\" data-end=\\\"2213\\\">BMW được ứng dụng hiệu quả trong xử l&yacute; bể phốt, ủ ph&acirc;n v&agrave; r&aacute;c thải hữu cơ, xử l&yacute; chất đệm l&oacute;t vật nu&ocirc;i v&agrave; cống r&atilde;nh. C&ocirc;ng nghệ n&agrave;y gi&uacute;p th&uacute;c đẩy qu&aacute; tr&igrave;nh ph&acirc;n hủy sinh học, giảm m&ugrave;i h&ocirc;i v&agrave; t&aacute;i tạo t&agrave;i nguy&ecirc;n, g&oacute;p phần giảm &ocirc; nhiễm v&agrave; bảo vệ m&ocirc;i trường sống.</p>\\n<h3 data-start=\\\"2215\\\" data-end=\\\"2252\\\">Ứng dụng trong đời sống hằng ng&agrave;y</h3>\\n<p data-start=\\\"2254\\\" data-end=\\\"2564\\\">Ngo&agrave;i c&aacute;c lĩnh vực sản xuất, nước sinh học BMW c&ograve;n được sử dụng trong đời sống hằng ng&agrave;y như khử m&ugrave;i v&agrave; vệ sinh khu vực nu&ocirc;i th&uacute; cưng, chăm s&oacute;c bể c&aacute;, cắm hoa, chăm s&oacute;c c&acirc;y cảnh, vệ sinh nh&agrave; bếp &ndash; ph&ograve;ng tắm v&agrave; giặt l&agrave;. C&aacute;c ứng dụng n&agrave;y gi&uacute;p cải thiện m&ocirc;i trường sống theo hướng an to&agrave;n, th&acirc;n thiện v&agrave; bền vững.</p>\\n<h3 data-start=\\\"2566\\\" data-end=\\\"2598\\\">Định hướng ứng dụng bền vững</h3>\\n<p data-start=\\\"2600\\\" data-end=\\\"2920\\\">Với t&iacute;nh chất sinh học tự nhi&ecirc;n v&agrave; khả năng ứng dụng đa lĩnh vực, c&ocirc;ng nghệ v&agrave; nước sinh học BMW đ&oacute;ng vai tr&ograve; quan trọng trong việc x&acirc;y dựng m&ocirc; h&igrave;nh sản xuất v&agrave; sinh hoạt tuần ho&agrave;n. Việc mở rộng v&agrave; nh&acirc;n rộng c&aacute;c ứng dụng BMW g&oacute;p phần bảo vệ m&ocirc;i trường, n&acirc;ng cao hiệu quả kinh tế v&agrave; hướng tới ph&aacute;t triển bền vững l&acirc;u d&agrave;i.</p>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 04:10:25','2026-01-09 04:07:35'),
(16,'{\"en\": \"EN\", \"ja\": \"JP\", \"vi\": \"Kết nối – Tư vấn – Đồng hành cùng giải pháp BMW\"}','ket-noi-tu-van-dong-hanh-cung-giai-phap-bmw','[14]',14,NULL,'[]','[]','[]','[]',0,12,1,1,NULL,'{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<p>C&ocirc;ng ty TNHH Giải ph&aacute;p M&ocirc;i trường Xanh Bền Vững Nhật Việt sẵn s&agrave;ng tiếp nhận th&ocirc;ng tin, tư vấn v&agrave; hợp t&aacute;c trong lĩnh vực c&ocirc;ng nghệ sinh học BMW, xử l&yacute; m&ocirc;i trường v&agrave; n&ocirc;ng nghiệp tuần ho&agrave;n. Vui l&ograve;ng li&ecirc;n hệ với ch&uacute;ng t&ocirc;i để được hỗ trợ chi tiết.</p>\"}','{\"en\": \"<p>EN</p>\", \"ja\": \"<p>JP</p>\", \"vi\": \"<h3 data-start=\\\"514\\\" data-end=\\\"587\\\">Li&ecirc;n hệ với C&ocirc;ng ty TNHH Giải ph&aacute;p M&ocirc;i trường Xanh Bền Vững Nhật Việt</h3>\\n<p data-start=\\\"589\\\" data-end=\\\"794\\\">C&ocirc;ng ty TNHH Giải ph&aacute;p M&ocirc;i trường Xanh Bền Vững Nhật Việt lu&ocirc;n sẵn s&agrave;ng lắng nghe v&agrave; đồng h&agrave;nh c&ugrave;ng kh&aacute;ch h&agrave;ng, đối t&aacute;c trong qu&aacute; tr&igrave;nh t&igrave;m hiểu, ứng dụng v&agrave; triển khai c&ocirc;ng nghệ sinh học BMW tại Việt Nam.</p>\\n<p data-start=\\\"796\\\" data-end=\\\"887\\\">Ch&uacute;ng t&ocirc;i tiếp nhận c&aacute;c nhu cầu tư vấn, hợp t&aacute;c v&agrave; triển khai giải ph&aacute;p trong c&aacute;c lĩnh vực:</p>\\n<ul data-start=\\\"889\\\" data-end=\\\"1075\\\">\\n<li data-start=\\\"889\\\" data-end=\\\"915\\\">\\n<p data-start=\\\"891\\\" data-end=\\\"915\\\">C&ocirc;ng nghệ sinh học BMW</p>\\n</li>\\n<li data-start=\\\"916\\\" data-end=\\\"945\\\">\\n<p data-start=\\\"918\\\" data-end=\\\"945\\\">Hệ thống xử l&yacute; m&ocirc;i trường</p>\\n</li>\\n<li data-start=\\\"946\\\" data-end=\\\"993\\\">\\n<p data-start=\\\"948\\\" data-end=\\\"993\\\">N&ocirc;ng nghiệp tuần ho&agrave;n v&agrave; n&ocirc;ng nghiệp hữu cơ</p>\\n</li>\\n<li data-start=\\\"994\\\" data-end=\\\"1036\\\">\\n<p data-start=\\\"996\\\" data-end=\\\"1036\\\">Chăn nu&ocirc;i, thủy sản v&agrave; xử l&yacute; chất thải</p>\\n</li>\\n<li data-start=\\\"1037\\\" data-end=\\\"1075\\\">\\n<p data-start=\\\"1039\\\" data-end=\\\"1075\\\">Ứng dụng nước sinh học đa năng BMW</p>\\n</li>\\n</ul>\\n<h3 data-start=\\\"1077\\\" data-end=\\\"1097\\\">Tư vấn v&agrave; hỗ trợ</h3>\\n<p data-start=\\\"1099\\\" data-end=\\\"1156\\\">Đội ngũ kỹ thuật v&agrave; tư vấn của ch&uacute;ng t&ocirc;i sẵn s&agrave;ng hỗ trợ:</p>\\n<ul data-start=\\\"1158\\\" data-end=\\\"1388\\\">\\n<li data-start=\\\"1158\\\" data-end=\\\"1212\\\">\\n<p data-start=\\\"1160\\\" data-end=\\\"1212\\\">Tư vấn giải ph&aacute;p ph&ugrave; hợp với từng m&ocirc; h&igrave;nh sản xuất</p>\\n</li>\\n<li data-start=\\\"1213\\\" data-end=\\\"1263\\\">\\n<p data-start=\\\"1215\\\" data-end=\\\"1263\\\">Hướng dẫn ứng dụng c&ocirc;ng nghệ BMW trong thực tế</p>\\n</li>\\n<li data-start=\\\"1264\\\" data-end=\\\"1327\\\">\\n<p data-start=\\\"1266\\\" data-end=\\\"1327\\\">Giải đ&aacute;p thắc mắc về kỹ thuật, vận h&agrave;nh v&agrave; hiệu quả sử dụng</p>\\n</li>\\n<li data-start=\\\"1328\\\" data-end=\\\"1388\\\">\\n<p data-start=\\\"1330\\\" data-end=\\\"1388\\\">Kết nối hợp t&aacute;c giữa doanh nghiệp, trang trại v&agrave; đối t&aacute;c</p>\\n</li>\\n</ul>\\n<p data-start=\\\"1390\\\" data-end=\\\"1467\\\">Mọi th&ocirc;ng tin li&ecirc;n hệ sẽ được tiếp nhận v&agrave; phản hồi trong thời gian sớm nhất.</p>\\n<h3 data-start=\\\"1469\\\" data-end=\\\"1490\\\">Th&ocirc;ng tin li&ecirc;n hệ</h3>\\n<p data-start=\\\"1492\\\" data-end=\\\"1704\\\">Qu&yacute; kh&aacute;ch h&agrave;ng v&agrave; đối t&aacute;c vui l&ograve;ng li&ecirc;n hệ với ch&uacute;ng t&ocirc;i th&ocirc;ng qua c&aacute;c k&ecirc;nh li&ecirc;n hệ được hiển thị tr&ecirc;n website, bao gồm điện thoại, Zalo hoặc biểu mẫu li&ecirc;n hệ trực tuyến, để được hỗ trợ nhanh ch&oacute;ng v&agrave; thuận tiện.</p>\\n<p data-start=\\\"1706\\\" data-end=\\\"1842\\\">Ch&uacute;ng t&ocirc;i cam kết cung cấp th&ocirc;ng tin minh bạch, tư vấn tận t&acirc;m v&agrave; đồng h&agrave;nh l&acirc;u d&agrave;i c&ugrave;ng kh&aacute;ch h&agrave;ng trong qu&aacute; tr&igrave;nh ph&aacute;t triển bền vững.</p>\"}',NULL,NULL,NULL,NULL,1,2,NULL,'2026-01-07 04:13:14','2026-01-09 04:01:59');

