/*Table structure for table `e_settings` */

DROP TABLE IF EXISTS `e_settings`;

CREATE TABLE `e_settings` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `setting_group` varchar(50) COLLATE utf8_unicode_ci NOT NULL,
  `setting_key` varchar(100) COLLATE utf8_unicode_ci NOT NULL,
  `setting_value` text COLLATE utf8_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `e_settings_setting_group_setting_key_unique` (`setting_group`,`setting_key`),
  KEY `e_settings_setting_group_index` (`setting_group`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

