/*Table structure for table `e_user_activities` */

DROP TABLE IF EXISTS `e_user_activities`;

CREATE TABLE `e_user_activities` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) unsigned DEFAULT NULL,
  `session_id` varchar(100) COLLATE utf8_unicode_ci NOT NULL,
  `ip_address` varchar(45) COLLATE utf8_unicode_ci DEFAULT NULL,
  `last_activity_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `e_user_activities_session_id_unique` (`session_id`),
  KEY `e_user_activities_user_id_foreign` (`user_id`),
  KEY `e_user_activities_session_id_index` (`session_id`),
  KEY `e_user_activities_last_activity_at_index` (`last_activity_at`),
  CONSTRAINT `e_user_activities_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

